export interface Node {
  id: string;
  text: string;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  parentId?: string;
  isGenerating?: boolean;
}

export interface Edge {
  id: string;
  source: string;
  target: string;
}

export interface CanvasState {
  nodes: Node[];
  edges: Edge[];
}

export enum NodeColor {
  BLUE = 'bg-blue-500',
  PURPLE = 'bg-purple-500',
  PINK = 'bg-pink-500',
  INDIGO = 'bg-indigo-500',
  SLATE = 'bg-slate-700',
}

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function expandThought(thought: string) {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Expand on this thought: "${thought}". Provide 3 to 5 related, concise sub-ideas or next steps.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            text: {
              type: Type.STRING,
              description: 'A concise related idea or expansion (max 10 words).',
            }
          },
          required: ["text"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || '[]');
  } catch (e) {
    console.error("Failed to parse AI response", e);
    return [];
  }
}

export async function summarizeFlow(thoughts: string[]) {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Summarize the following brainstorming path into a single cohesive vision statement: ${thoughts.join(' -> ')}`,
  });

  return response.text;
}

import React, { useState, useRef, useEffect } from 'react';
import { Node } from '../types';

interface NodeItemProps {
  node: Node;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onUpdate: (id: string, updates: Partial<Node>) => void;
  onExpand: (id: string) => void;
  onDelete: (id: string) => void;
}

export const NodeItem: React.FC<NodeItemProps> = ({ 
  node, 
  isSelected, 
  onSelect, 
  onUpdate, 
  onExpand,
  onDelete
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragOffset = useRef({ x: 0, y: 0 });

  const handleMouseDown = (e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(node.id);
    setIsDragging(true);
    dragOffset.current = {
      x: e.clientX - node.x,
      y: e.clientY - node.y
    };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        onUpdate(node.id, {
          x: e.clientX - dragOffset.current.x,
          y: e.clientY - dragOffset.current.y
        });
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, node.id, onUpdate]);

  return (
    <div
      onMouseDown={handleMouseDown}
      className={`absolute cursor-move select-none rounded-xl p-4 shadow-xl border-2 transition-shadow duration-200 ${
        isSelected ? 'border-indigo-500 ring-2 ring-indigo-200' : 'border-transparent'
      } ${node.color} text-white flex flex-col items-center justify-center min-w-[150px] max-w-[250px]`}
      style={{
        left: node.x,
        top: node.y,
        zIndex: isSelected ? 50 : 10,
      }}
    >
      {node.isGenerating && (
        <div className="absolute inset-0 bg-white/20 animate-pulse rounded-xl" />
      )}

      <textarea
        className="bg-transparent border-none outline-none text-center font-medium w-full resize-none placeholder-white/50"
        value={node.text}
        onChange={(e) => onUpdate(node.id, { text: e.target.value })}
        rows={2}
        placeholder="Type a thought..."
      />

      <div className="flex gap-2 mt-3 pt-2 border-t border-white/20 w-full justify-center">
        <button
          onClick={(e) => { e.stopPropagation(); onExpand(node.id); }}
          className="p-1 hover:bg-white/20 rounded transition-colors text-xs flex items-center gap-1"
          title="AI Expand"
          disabled={node.isGenerating}
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
          Expand
        </button>
        <button
          onClick={(e) => { e.stopPropagation(); onDelete(node.id); }}
          className="p-1 hover:bg-red-500/50 rounded transition-colors text-xs"
          title="Delete"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
          </svg>
        </button>
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { Node, Edge, NodeColor } from './types';
import { Header } from './components/Header';
import { NodeItem } from './components/NodeItem';
import { expandThought, summarizeFlow } from './services/geminiService';

const COLORS = [NodeColor.BLUE, NodeColor.PURPLE, NodeColor.PINK, NodeColor.INDIGO];

const App: React.FC = () => {
  const [nodes, setNodes] = useState<Node[]>([]);
  const [edges, setEdges] = useState<Edge[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [summary, setSummary] = useState<string | null>(null);

  // Load from local storage
  useEffect(() => {
    const saved = localStorage.getItem('thinkflow_state');
    if (saved) {
      try {
        const { nodes: n, edges: e } = JSON.parse(saved);
        setNodes(n);
        setEdges(e);
      } catch (err) {
        console.error("Failed to load state", err);
      }
    }
  }, []);

  // Save to local storage
  useEffect(() => {
    localStorage.setItem('thinkflow_state', JSON.stringify({ nodes, edges }));
  }, [nodes, edges]);

  const addNode = useCallback((x?: number, y?: number, parentId?: string, text?: string) => {
    const newNode: Node = {
      id: Math.random().toString(36).substr(2, 9),
      text: text || '',
      x: x || window.innerWidth / 2 - 75,
      y: y || window.innerHeight / 2 - 50,
      width: 150,
      height: 100,
      color: COLORS[Math.floor(Math.random() * COLORS.length)],
      parentId,
    };
    setNodes(prev => [...prev, newNode]);
    if (parentId) {
      const newEdge: Edge = {
        id: `e-${parentId}-${newNode.id}`,
        source: parentId,
        target: newNode.id,
      };
      setEdges(prev => [...prev, newEdge]);
    }
    return newNode.id;
  }, []);

  const updateNode = useCallback((id: string, updates: Partial<Node>) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, ...updates } : n));
  }, []);

  const deleteNode = useCallback((id: string) => {
    setNodes(prev => prev.filter(n => n.id !== id));
    setEdges(prev => prev.filter(e => e.source !== id && e.target !== id));
    if (selectedId === id) setSelectedId(null);
  }, [selectedId]);

  const handleExpand = async (id: string) => {
    const node = nodes.find(n => n.id === id);
    if (!node || !node.text.trim()) return;

    updateNode(id, { isGenerating: true });
    try {
      const suggestions = await expandThought(node.text);
      suggestions.forEach((suggestion: { text: string }, index: number) => {
        const angle = (index / suggestions.length) * Math.PI * 2;
        const radius = 250;
        const x = node.x + Math.cos(angle) * radius;
        const y = node.y + Math.sin(angle) * radius;
        addNode(x, y, id, suggestion.text);
      });
    } catch (err) {
      console.error("AI expansion failed", err);
    } finally {
      updateNode(id, { isGenerating: false });
    }
  };

  const handleSummarize = async () => {
    if (nodes.length === 0) return;
    const allTexts = nodes.map(n => n.text).filter(t => t.length > 0);
    if (allTexts.length === 0) return;

    setSummary("Synthesizing your thoughts...");
    try {
      const result = await summarizeFlow(allTexts);
      setSummary(result || "Could not generate summary.");
    } catch (err) {
      setSummary("Error generating summary.");
    }
  };

  const clearCanvas = () => {
    if (confirm("Are you sure you want to clear the entire canvas?")) {
      setNodes([]);
      setEdges([]);
      setSummary(null);
    }
  };

  return (
    <div className="relative w-screen h-screen overflow-hidden canvas-dots">
      <Header 
        onAddNode={() => addNode()} 
        onClear={clearCanvas}
        onSummarize={handleSummarize}
      />

      {/* SVG Connections */}
      <svg className="absolute inset-0 pointer-events-none w-full h-full">
        <defs>
          <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="0" refY="3.5" orient="auto">
            <polygon points="0 0, 10 3.5, 0 7" fill="#cbd5e1" />
          </marker>
        </defs>
        {edges.map(edge => {
          const source = nodes.find(n => n.id === edge.source);
          const target = nodes.find(n => n.id === edge.target);
          if (!source || !target) return null;

          const startX = source.x + 100;
          const startY = source.y + 50;
          const endX = target.x + 100;
          const endY = target.y + 50;

          return (
            <line
              key={edge.id}
              x1={startX}
              y1={startY}
              x2={endX}
              y2={endY}
              stroke="#cbd5e1"
              strokeWidth="2"
              markerEnd="url(#arrowhead)"
            />
          );
        })}
      </svg>

      {/* Nodes */}
      {nodes.map(node => (
        <NodeItem
          key={node.id}
          node={node}
          isSelected={selectedId === node.id}
          onSelect={setSelectedId}
          onUpdate={updateNode}
          onExpand={handleExpand}
          onDelete={deleteNode}
        />
      ))}

      {/* Empty State */}
      {nodes.length === 0 && (
        <div className="absolute inset-0 flex items-center justify-center flex-col text-slate-400 pointer-events-none">
          <svg className="w-16 h-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
          </svg>
          <p className="text-lg font-light">Double click or click 'New Thought' to begin</p>
        </div>
      )}

      {/* Summary Modal */}
      {summary && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[100] flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full p-8 relative animate-in fade-in zoom-in duration-300">
            <button 
              onClick={() => setSummary(null)}
              className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 transition-colors"
            >
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
            <h3 className="text-xl font-bold mb-4 text-indigo-600">Thought Summary</h3>
            <div className="text-slate-700 leading-relaxed italic">
              "{summary}"
            </div>
            <div className="mt-8 flex justify-end">
              <button 
                onClick={() => setSummary(null)}
                className="px-6 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Instructions Overlay */}
      <div className="fixed bottom-6 right-6 text-xs text-slate-400 bg-white/80 backdrop-blur border px-3 py-2 rounded-lg pointer-events-none">
        Drag to move • Click AI Expand to grow ideas • Press Delete to remove
      </div>
    </div>
  );
};

export default App;

