export type Language = 'en' | 'ru' | 'uz';

export type StudentClass = '7A' | '7B' | '8A' | '8B' | '9A' | '9B' | '10A' | '10B' | '11A' | '11B';

export interface UserProfile {
  email: string;
  name: string;
  age: number;
  photo?: string;
  interests: string[];
  studentClass: StudentClass;
  language: Language;
  xp: number;
  level: number;
  isAdmin: boolean;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface Task {
  id: string;
  title: string;
  difficulty: 'easy' | 'medium' | 'challenge';
  description: string;
  xpReward: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, Language } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const getSystemInstruction = (role: 'teacher' | 'coach' | 'trainer', profile: UserProfile) => {
  const interests = profile.interests.join(', ');
  const lang = profile.language === 'ru' ? 'Russian' : profile.language === 'uz' ? 'Uzbek' : 'English';

  const base = `Respond in ${lang}. The student is in class ${profile.studentClass} and loves ${interests}. `;

  if (role === 'teacher') {
    return base + `You are a Concept Teacher. Explain complex topics ONLY through metaphors related to the student's interests (${interests}). Simplify, but don't give the final answer if it's a problem-solving request.`;
  }
  if (role === 'coach') {
    return base + `You are a Socratic Coach. Never give direct answers. Ask 1-2 powerful questions that guide the student's thinking. If they are wrong, encourage them to rethink the logic.`;
  }
  return base + `You are an Adaptive Trainer. Generate a small learning task or question. Do not provide the solution. Evaluate their response based on reasoning, not just correctness. Reward them with encouragement.`;
};

export async function askAI(role: 'teacher' | 'coach' | 'trainer', prompt: string, profile: UserProfile, history: any[] = []) {
  const ai = getAI();
  const instruction = getSystemInstruction(role, profile);

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
    config: {
      systemInstruction: instruction,
    }
  });

  return response.text;
}

export async function generateAdaptiveTask(profile: UserProfile) {
  const ai = getAI();
  const lang = profile.language === 'ru' ? 'Russian' : profile.language === 'uz' ? 'Uzbek' : 'English';

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Generate a unique learning task for a student in class ${profile.studentClass} who likes ${profile.interests.join(', ')}. Respond in JSON. Language: ${lang}.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          difficulty: { type: Type.STRING, enum: ['easy', 'medium', 'challenge'] },
          description: { type: Type.STRING },
          xpReward: { type: Type.NUMBER }
        },
        required: ["title", "difficulty", "description", "xpReward"]
      }
    }
  });

  return JSON.parse(response.text);
}

