  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeRole, setActiveRole] = useState<'teacher' | 'coach' | 'trainer'>('teacher');
  const [allStudents, setAllStudents] = useState<UserProfile[]>([]);
  const [currentTask, setCurrentTask] = useState<Task | null>(null);
  const [tempLang, setTempLang] = useState<Language>('ru');

  useEffect(() => {
    const savedUser = localStorage.getItem('thinkflow_user');
    const savedStudents = localStorage.getItem('thinkflow_all_students');
    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedStudents) setAllStudents(JSON.parse(savedStudents));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('thinkflow_user', JSON.stringify(user));
    if (allStudents.length > 0) localStorage.setItem('thinkflow_all_students', JSON.stringify(allStudents));
  }, [user, allStudents]);

  const t = useMemo(() => TRANSLATIONS[user?.language || tempLang], [user, tempLang]);

  const handleAuth = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const email = formData.get('email') as string;
    const password = formData.get('password') as string;

    if (authMode === 'register') {
      const interests = INTERESTS_POOL.filter(i => formData.get(`interest-${i}`));
      const newUser: UserProfile = {
        email,
        name: formData.get('name') as string,
        studentClass: formData.get('class') as StudentClass,
        language: formData.get('language') as Language,
        interests: interests.length > 0 ? interests : ['Science'],
        xp: 0,
        level: 1,
        isAdmin: email === 'skwinskwinskwin@gmail.com' && password === 'sarvar12123333232111'
      };
      setUser(newUser);
      setAllStudents(prev => [...prev.filter(s => s.email !== newUser.email), newUser]);
    } else {
      // Simple simulation of login
      const found = allStudents.find(s => s.email === email);
      if (found) {
        setUser(found);
      } else if (email === 'skwinskwinskwin@gmail.com' && password === 'sarvar12123333232111') {
         const adminUser: UserProfile = {
            email, name: "Admin", studentClass: '11B', language: 'en', interests: ['Business'], xp: 9999, level: 100, isAdmin: true
         };
         setUser(adminUser);
      } else {
        alert("Account not found. Please register.");
        setAuthMode('register');
      }
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || !user) return;
    const userMsg: Message = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    try {
      const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const response = await askAI(activeRole, input, user, history);
      const aiMsg: Message = { role: 'model', text: response || '', timestamp: Date.now() };
      setMessages(prev => [...prev, aiMsg]);
      const newXp = user.xp + 15;
      setUser({ ...user, xp: newXp, level: Math.floor(newXp / 100) + 1 });
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const getNewTask = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      const task = await generateAdaptiveTask(user);
      setCurrentTask(task);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  if (!user) {
    if (authMode === 'landing') {
      return (
        <div className="min-h-screen bg-main-gradient flex flex-col items-center justify-center p-6">
          <div className="max-w-4xl w-full text-center space-y-12 animate-in fade-in zoom-in duration-700">
            <div className="space-y-4">
              <div className="inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold uppercase tracking-widest mb-4">
                Powered by Gemini 3 Pro
              </div>
              <h1 className="text-6xl md:text-8xl font-extrabold tracking-tight leading-none">
                <span className="text-white">Learn With </span>
                <span className="text-gradient">Precision.</span>
              </h1>
              <p className="text-xl text-slate-400 max-w-2xl mx-auto leading-relaxed">
                {t.heroSub}
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="glass p-8 rounded-3xl text-left border-indigo-500/20">
                <div className="w-12 h-12 bg-blue-500/20 rounded-2xl flex items-center justify-center text-blue-400 mb-6 text-2xl">🧠</div>
                <h3 className="font-bold text-lg mb-2">{t.teacher}</h3>
                <p className="text-sm text-slate-400">Complex concepts explained through your personal hobbies and interests.</p>
              </div>
              <div className="glass p-8 rounded-3xl text-left border-purple-500/20">
                <div className="w-12 h-12 bg-purple-500/20 rounded-2xl flex items-center justify-center text-purple-400 mb-6 text-2xl">🔍</div>
                <h3 className="font-bold text-lg mb-2">{t.coach}</h3>
                <p className="text-sm text-slate-400">A Socratic guide that asks the right questions to make you think, not just solve.</p>
              </div>
              <div className="glass p-8 rounded-3xl text-left border-pink-500/20">
                <div className="w-12 h-12 bg-pink-500/20 rounded-2xl flex items-center justify-center text-pink-400 mb-6 text-2xl">⚡</div>
                <h3 className="font-bold text-lg mb-2">{t.trainer}</h3>
                <p className="text-sm text-slate-400">Adaptive challenges that evolve with your performance and class level.</p>
              </div>
            </div>

            <div className="flex flex-col md:flex-row gap-4 justify-center items-center">
              <button onClick={() => setAuthMode('register')} className="btn-gradient px-12 py-4 rounded-2xl font-bold text-white shadow-xl w-full md:w-auto">
                {t.register}
              </button>
              <button onClick={() => setAuthMode('login')} className="px-12 py-4 rounded-2xl font-bold glass hover:bg-white/10 transition-all w-full md:w-auto">
                {t.login}
              </button>
            </div>

            <div className="flex justify-center gap-4 text-xs font-bold text-slate-500">
              <button onClick={() => setTempLang('ru')} className={tempLang === 'ru' ? 'text-indigo-400' : ''}>RU</button>
              <button onClick={() => setTempLang('en')} className={tempLang === 'en' ? 'text-indigo-400' : ''}>EN</button>
              <button onClick={() => setTempLang('uz')} className={tempLang === 'uz' ? 'text-indigo-400' : ''}>UZ</button>
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="min-h-screen bg-main-gradient flex items-center justify-center p-4">
        <form onSubmit={handleAuth} className="glass p-10 rounded-3xl max-w-lg w-full shadow-2xl space-y-6 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 shimmer pointer-events-none" />
          <h2 className="text-3xl font-extrabold text-center text-gradient">
            {authMode === 'register' ? t.register : t.login}
          </h2>

          <div className="space-y-4">
            <div className="grid grid-cols-1 gap-4">
              {authMode === 'register' && (
                <input name="name" placeholder="Full Name" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm focus:ring-2 ring-indigo-500 outline-none" />
              )}
              <input name="email" type="email" placeholder="Email" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm focus:ring-2 ring-indigo-500 outline-none" />
              <input name="password" type="password" placeholder="Password" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm focus:ring-2 ring-indigo-500 outline-none" />
            </div>

            {authMode === 'register' && (
              <>
                <div className="flex gap-4">
                  <select name="class" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm flex-1">
                    {CLASSES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                  <select name="language" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm flex-1">
                    <option value="en">English</option>
                    <option value="ru">Русский</option>
                    <option value="uz">O'zbekcha</option>
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Select Interests</label>
                  <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto p-2 bg-slate-950/50 rounded-xl border border-slate-700/50">
                    {INTERESTS_POOL.map(i => (
                      <label key={i} className="flex items-center gap-1 bg-slate-800/80 px-2.5 py-1.5 rounded-lg text-[10px] cursor-pointer hover:bg-indigo-500/20 transition-all border border-transparent peer-checked:border-indigo-500">
                        <input type="checkbox" name={`interest-${i}`} className="hidden peer" />
                        <span className="peer-checked:text-indigo-400 font-bold">{i}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>

          <button type="submit" className="w-full btn-gradient py-4 rounded-xl font-black text-sm uppercase tracking-widest shadow-lg">
            {authMode === 'register' ? t.register : t.login}
          </button>

          <button type="button" onClick={() => setAuthMode(authMode === 'register' ? 'login' : 'register')} className="w-full text-slate-500 text-xs hover:text-indigo-400 transition-colors">
            {authMode === 'register' ? t.hasAccount : t.noAccount}
          </button>

          <button type="button" onClick={() => setAuthMode('landing')} className="w-full text-slate-600 text-[10px] mt-4">← Back to Home</button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex overflow-hidden">
      {/* Sidebar with Gradient borders */}
      <nav className="w-64 bg-slate-900/40 backdrop-blur-xl border-r border-slate-800/50 flex flex-col p-6 space-y-10 relative z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 btn-gradient rounded-xl flex items-center justify-center font-black text-xl italic shadow-lg">T</div>
          <div>
            <h2 className="font-black text-lg tracking-tight">ThinkFlow</h2>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest">Active State</p>
          </div>
        </div>

        <div className="space-y-3">
          <NavItem icon="⚡" label={t.learn} active={view === 'learn'} onClick={() => setView('learn')} />
          <NavItem icon="🎯" label={t.tasks} active={view === 'tasks'} onClick={() => setView('tasks')} />
          <NavItem icon="🎖️" label={t.leaderboard} active={view === 'leaderboard'} onClick={() => setView('leaderboard')} />
          <NavItem icon="✨" label={t.profile} active={view === 'profile'} onClick={() => setView('profile')} />
          {user.isAdmin && <NavItem icon="🛡️" label={t.admin} active={view === 'admin'} onClick={() => setView('admin')} />}
        </div>

        <div className="mt-auto glass p-5 rounded-2xl border-indigo-500/10 space-y-4">
          <div className="flex justify-between items-end">
            <div>
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">{t.level}</p>
              <p className="text-2xl font-black text-indigo-400 leading-none">{user.level}</p>
            </div>
            <div className="text-right">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">{t.xp}</p>
              <p className="text-xs font-bold text-white">{user.xp}</p>
            </div>
          </div>
          <div className="w-full h-2 bg-slate-800 rounded-full overflow-hidden">
            <div className="h-full btn-gradient" style={{ width: `${user.xp % 100}%` }} />
          </div>
          <p className="text-[10px] text-slate-400 text-center font-bold">{user.name}</p>
        </div>
      </nav>

      {/* Content */}
      <main className="flex-1 flex flex-col bg-slate-950">
        <header className="h-20 border-b border-slate-800/50 flex items-center justify-between px-10 bg-slate-950/50 backdrop-blur-md">
          <h2 className="text-xl font-black uppercase tracking-widest text-slate-400">{view}</h2>
          <div className="flex items-center gap-4">
            <div className="px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-[10px] font-black uppercase tracking-widest">
              {user.studentClass} SEC
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 relative">
          <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-600/5 blur-[120px] rounded-full pointer-events-none" />

          {view === 'learn' && (
            <div className="max-w-4xl mx-auto flex flex-col h-full space-y-8 animate-in slide-in-from-bottom duration-500">
              <div className="flex gap-4 justify-center">
                <RoleBtn active={activeRole === 'teacher'} label={t.teacher} onClick={() => setActiveRole('teacher')} color="btn-gradient" />
                <RoleBtn active={activeRole === 'coach'} label={t.coach} onClick={() => setActiveRole('coach')} color="bg-amber-500 shadow-amber-500/20" />
                <RoleBtn active={activeRole === 'trainer'} label={t.trainer} onClick={() => setActiveRole('trainer')} color="bg-emerald-500 shadow-emerald-500/20" />
              </div>

              <div className="flex-1 glass rounded-3xl p-8 overflow-y-auto space-y-6 flex flex-col border-slate-800/50 shadow-inner">
                {messages.length === 0 && (
                  <div className="flex-1 flex flex-col items-center justify-center text-slate-600 text-center space-y-4">
                    <div className="w-20 h-20 bg-indigo-500/5 rounded-full flex items-center justify-center text-5xl">🔭</div>
                    <p className="font-bold">{t.welcome}, {user.name}!</p>
                    <p className="text-sm max-w-xs">{t.heroSub}</p>
                  </div>
                )}
                {messages.map((m, i) => (
                  <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[75%] rounded-3xl p-5 text-sm leading-relaxed ${m.role === 'user' ? 'btn-gradient font-bold shadow-lg' : 'glass border-slate-700/50'}`}>
                      {m.text}
                    </div>
                  </div>
                ))}
                {isLoading && <div className="text-[10px] text-indigo-400 font-black animate-pulse uppercase tracking-[0.2em]">ThinkFlow Architect Responding...</div>}
              </div>

              <div className="flex gap-3">
                <input 
                  value={input}
                  onChange={e => setInput(e.target.value)}
                  onKeyPress={e => e.key === 'Enter' && handleSendMessage()}
                  placeholder={t.startThinking}
                  className="flex-1 bg-slate-900 border border-slate-800/50 rounded-2xl px-6 py-4 outline-none focus:ring-2 ring-indigo-500 transition-all font-medium placeholder:text-slate-700"
                />
                <button onClick={handleSendMessage} className="btn-gradient px-8 rounded-2xl font-black uppercase text-xs tracking-widest">Submit</button>
              </div>
            </div>
          )}

          {view === 'tasks' && (
            <div className="max-w-2xl mx-auto space-y-10 py-10 animate-in slide-in-from-right duration-500">
              {!currentTask ? (
                <div className="text-center space-y-8 glass p-12 rounded-[40px] border-emerald-500/10">
                  <div className="w-24 h-24 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto text-5xl">🐉</div>
                  <h3 className="text-3xl font-black tracking-tight">Adaptive Mission Control</h3>
                  <p className="text-slate-400 italic">"I generate challenges based on your physics and coding interests."</p>
                  <button onClick={getNewTask} disabled={isLoading} className="bg-emerald-600 hover:bg-emerald-500 px-12 py-4 rounded-2xl font-black text-white shadow-xl shadow-emerald-500/20 transition-all disabled:opacity-50">
                    {isLoading ? 'Synthesizing...' : t.trainBrain}
                  </button>
                </div>
              ) : (
                <div className="glass border-2 border-emerald-500/30 rounded-[40px] p-10 space-y-6 relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 blur-[50px]" />
                  <div className="flex justify-between items-center">
                    <span className="px-4 py-1 bg-emerald-500/20 text-emerald-400 rounded-full text-[10px] uppercase font-black tracking-widest">{currentTask.difficulty}</span>
                    <span className="text-indigo-400 font-black">+{currentTask.xpReward} XP</span>
                  </div>
                  <h3 className="text-3xl font-black leading-tight tracking-tight">{currentTask.title}</h3>
                  <p className="text-slate-400 leading-relaxed text-lg">{currentTask.description}</p>
                  <div className="pt-6 flex gap-4">
                    <button onClick={() => { setActiveRole('trainer'); setView('learn'); }} className="flex-1 btn-gradient py-4 rounded-2xl font-black uppercase text-xs tracking-widest">Accept Mission</button>
                    <button onClick={() => setCurrentTask(null)} className="px-6 py-4 glass rounded-2xl text-xs font-bold text-slate-500">Refresh</button>
                  </div>
                </div>
              )}
            </div>
          )}

          {view === 'leaderboard' && (
            <div className="max-w-3xl mx-auto space-y-6 py-6 animate-in zoom-in duration-500">
              <h3 className="text-3xl font-black tracking-tight mb-8">Global Hall of Fame</h3>
              {allStudents.sort((a, b) => b.xp - a.xp).map((student, i) => (
                <div key={i} className={`flex items-center justify-between p-6 rounded-3xl border transition-all ${student.email === user.email ? 'bg-indigo-600/20 border-indigo-500/50 shadow-lg shadow-indigo-500/10' : 'glass border-slate-800/50 hover:border-slate-700'}`}>
                  <div className="flex items-center gap-6">
                    <span className={`font-black text-2xl w-8 text-center ${i < 3 ? 'text-indigo-400' : 'text-slate-600'}`}>#{i+1}</span>
                    <div className="w-14 h-14 btn-gradient rounded-2xl flex items-center justify-center font-black text-xl shadow-md">{student.name[0]}</div>
                    <div>
                      <p className="font-extrabold text-lg">{student.name}</p>
                      <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{student.studentClass} Class • Lvl {student.level}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <span className="font-mono font-black text-xl text-indigo-400 tracking-tighter">{student.xp}</span>
                    <p className="text-[8px] text-slate-600 font-black uppercase">Points</p>
                  </div>
                </div>
              ))}
            </div>
          )}

          {view === 'profile' && (
            <div className="max-w-2xl mx-auto glass border-slate-800/50 rounded-[40px] p-12 space-y-12 animate-in fade-in duration-700 relative overflow-hidden">
              <div className="absolute -top-24 -left-24 w-64 h-64 bg-indigo-500/10 blur-[80px] rounded-full" />
              <div className="flex items-center gap-8 relative z-10">
                <div className="w-32 h-32 btn-gradient rounded-[32px] flex items-center justify-center text-5xl font-black shadow-2xl">{user.name[0]}</div>
                <div className="space-y-2">
                  <h3 className="text-4xl font-black tracking-tight leading-none">{user.name}</h3>
                  <p className="text-slate-500 font-medium">{user.email}</p>
                  <div className="flex gap-2 pt-2">
                    <span className="px-4 py-1 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-[10px] font-black tracking-widest text-indigo-400">{user.studentClass} SEC</span>
                    <span className="px-4 py-1 bg-slate-800 border border-slate-700 rounded-full text-[10px] font-black tracking-widest text-slate-400 uppercase">{user.language}</span>
                  </div>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-6 relative z-10">
                <ProfileStat label="Current Rank" value={`Lvl ${user.level}`} />
                <ProfileStat label="Think Score" value={`${user.xp} XP`} />
                <ProfileStat label="Brain Output" value={`${(user.level * 1.5).toFixed(1)} PFlop`} />
                <ProfileStat label="Deep Links" value={Math.floor(user.xp / 45)} />
              </div>
              <div className="space-y-4 relative z-10">
                <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em]">Knowledge Lenses</h4>
                <div className="flex flex-wrap gap-3">
                  {user.interests.map(i => <span key={i} className="px-4 py-2 glass rounded-2xl text-[10px] font-black uppercase tracking-widest text-indigo-300 border-indigo-500/20 shadow-sm">{i}</span>)}
                </div>
              </div>
              <button onClick={() => { localStorage.clear(); window.location.reload(); }} className="w-full text-slate-600 text-[10px] uppercase font-black tracking-widest hover:text-red-500 transition-colors pt-6">Sign Out & Wipe Data</button>
            </div>
          )}

          {view === 'admin' && user.isAdmin && (
            <div className="max-w-5xl mx-auto space-y-8 py-4">
               <h3 className="text-3xl font-black tracking-tight">Student Command Center</h3>
               <div className="glass border-slate-800 rounded-[40px] overflow-hidden shadow-2xl">
                 <table className="w-full text-left">
                   <thead className="bg-slate-900/80 text-slate-500 text-[10px] uppercase font-black tracking-[0.2em]">
                     <tr>
                       <th className="p-6">Student Entity</th>
                       <th className="p-6">Origin Email</th>
                       <th className="p-6">Class Assignment</th>
                       <th className="p-6">Authorization</th>
                     </tr>
                   </thead>
                   <tbody className="text-sm">
                     {allStudents.map(student => (
                       <tr key={student.email} className="border-t border-slate-800/50 hover:bg-white/[0.02] transition-colors">
                         <td className="p-6 font-extrabold">{student.name}</td>
                         <td className="p-6 text-slate-500 font-mono text-xs">{student.email}</td>
                         <td className="p-6 font-black text-indigo-400">{student.studentClass}</td>
                         <td className="p-6">
                           <button 
                             onClick={() => setAllStudents(prev => prev.filter(s => s.email !== student.email))}
                             className="text-red-500/50 hover:text-red-500 font-black text-[10px] uppercase tracking-widest transition-all"
                           >
                             Terminate
                           </button>
                         </td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon, label, active, onClick }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all ${active ? 'nav-active text-indigo-400 font-black' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/30'}`}>
    <span className="text-xl">{icon}</span>
    <span className="font-bold text-xs uppercase tracking-widest">{label}</span>
  </button>
);

const RoleBtn = ({ active, label, onClick, color }: any) => (
  <button 
    onClick={onClick} 
    className={`px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all border-2 ${active ? `${color} text-white border-transparent` : 'bg-transparent text-slate-600 border-slate-800 hover:border-slate-700'}`}
  >
    {label}
  </button>
);

const ProfileStat = ({ label, value }: any) => (
  <div className="glass p-6 rounded-3xl border-slate-800/30 shadow-sm flex flex-col items-center text-center">
    <p className="text-[9px] text-slate-500 uppercase font-black tracking-[0.2em] mb-1">{label}</p>
    <p className="text-2xl font-black text-white">{value}</p>
  </div>
);

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { UserProfile, Language, StudentClass, Message, Task } from './types';
import { askAI, generateAdaptiveTask } from './services/geminiService';

const INTERESTS_POOL = [
  'Sports', 'Football', 'Chess', 'Anime', 'Music', 'Design', 'Coding', 
  'Cooking', 'Cars', 'Business', 'Gaming', 'Movies', 'Art', 'Fitness', 'Science'
];

const CLASSES: StudentClass[] = ['7A', '7B', '8A', '8B', '9A', '9B', '10A', '10B', '11A', '11B'];

const TRANSLATIONS = {
  en: {
    heroTitle: "Unlock Your Thinking Potential",
    heroSub: "ThinkFlow is your personal AI mentor that explains complex concepts through the things you love.",
    learn: "Explore",
    tasks: "Challenges",
    leaderboard: "Hall of Fame",
    profile: "Self",
    admin: "Admin Console",
    xp: "XP",
    level: "Lvl",
    class: "Sect",
    interests: "Interests",
    register: "Start Journey",
    login: "Sign In",
    noAccount: "New student? Register",
    hasAccount: "Already a member? Login",
    startThinking: "Ask anything...",
    trainBrain: "New Mission",
    welcome: "Welcome",
    teacher: "The Mentor",
    coach: "The Coach",
    trainer: "The Architect",
  },
  ru: {
    heroTitle: "Раскрой свой потенциал мышления",
    heroSub: "ThinkFlow — это твой личный ИИ-наставник, который объясняет сложные темы через то, что ты любишь.",
    learn: "Обучение",
    tasks: "Миссии",
    leaderboard: "Зал славы",
    profile: "Профиль",
    admin: "Админ-панель",
    xp: "XP",
    level: "Ур",
    class: "Класс",
    interests: "Интересы",
    register: "Начать путь",
    login: "Войти",
    noAccount: "Новый ученик? Регистрация",
    hasAccount: "Уже есть аккаунт? Войти",
    startThinking: "Спроси о чем угодно...",
    trainBrain: "Новая миссия",
    welcome: "Добро пожаловать",
    teacher: "Наставник",
    coach: "Коуч",
    trainer: "Архитектор",
  },
  uz: {
    heroTitle: "Fikrlash qobiliyatingni och",
    heroSub: "ThinkFlow — bu sizning shaxsiy AI ustozi bo'lib, u murakkab mavzularni siz yoqtirgan narsalar orqali tushuntiradi.",
    learn: "O'rganish",
    tasks: "Vazifalar",
    leaderboard: "Reyting",
    profile: "Profil",
    admin: "Admin",
    xp: "XP",
    level: "Daj",
    class: "Sinf",
    interests: "Qiziqishlar",
    register: "Boshlash",
    login: "Kirish",
    noAccount: "Yangi talabamisiz? Ro'yxatdan o'ting",
    hasAccount: "Akkauntingiz bormi? Kirish",
    startThinking: "Har qanday narsani so'rang...",
    trainBrain: "Yangi topshiriq",
    welcome: "Xush kelibsiz",
    teacher: "Ustoz",
    coach: "Murabbiy",
    trainer: "Arxitektor",
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [authMode, setAuthMode] = useState<'landing' | 'login' | 'register'>('landing');
  const [view, setView] = useState<'learn' | 'tasks' | 'leaderboard' | 'profile' | 'admin'>('learn');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeRole, setActiveRole] = useState<'teacher' | 'coach' | 'trainer'>('teacher');
  const [allStudents, setAllStudents] = useState<UserProfile[]>([]);
  const [currentTask, setCurrentTask] = useState<Task | null>(null);
  const [tempLang, setTempLang] = useState<Language>('ru');

  useEffect(() => {
    const savedUser = localStorage.getItem('thinkflow_user');
    const savedStudents = localStorage.getItem('thinkflow_all_students');
    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedStudents) setAllStudents(JSON.parse(savedStudents));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('thinkflow_user', JSON.stringify(user));
    if (allStudents.length > 0) localStorage.setItem('thinkflow_all_students', JSON.stringify(allStudents));
  }, [user, allStudents]);

  const t = useMemo(() => TRANSLATIONS[user?.language || tempLang], [user, tempLang]);

  const handleAuth = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const email = formData.get('email') as string;
    const password = formData.get('password') as string;

    if (authMode === 'register') {
      const interests = INTERESTS_POOL.filter(i => formData.get(`interest-${i}`));
      const newUser: UserProfile = {
        email,
        name: formData.get('name') as string,
        studentClass: formData.get('class') as StudentClass,
        language: formData.get('language') as Language,
        interests: interests.length > 0 ? interests : ['Science'],
        xp: 0,
        level: 1,
        isAdmin: email === 'skwinskwinskwin@gmail.com' && password === 'sarvar12123333232111'
      };
      setUser(newUser);
      setAllStudents(prev => [...prev.filter(s => s.email !== newUser.email), newUser]);
    } else {
      const found = allStudents.find(s => s.email === email);
      if (found) {
        setUser(found);
      } else if (email === 'skwinskwinskwin@gmail.com' && password === 'sarvar12123333232111') {
         const adminUser: UserProfile = {
            email, name: "Admin", studentClass: '11B', language: 'en', interests: ['Business'], xp: 9999, level: 100, isAdmin: true
         };
         setUser(adminUser);
      } else {
        alert("Account not found. Please register.");
        setAuthMode('register');
      }
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || !user) return;
    const userMsg: Message = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    try {
      const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const response = await askAI(activeRole, input, user, history);
      const aiMsg: Message = { role: 'model', text: response || '', timestamp: Date.now() };
      setMessages(prev => [...prev, aiMsg]);
      const newXp = user.xp + 15;
      setUser({ ...user, xp: newXp, level: Math.floor(newXp / 100) + 1 });
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const getNewTask = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      const task = await generateAdaptiveTask(user);
      setCurrentTask(task);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  if (!user) {
    if (authMode === 'landing') {
      return (
        <div className="min-h-screen bg-main-gradient flex flex-col items-center overflow-y-auto p-6">
          {/* Top Header with Language Picker */}
          <header className="w-full max-w-6xl flex justify-between items-center py-6 mb-12">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 btn-gradient rounded-lg flex items-center justify-center font-black italic shadow-lg">T</div>
              <span className="font-black text-xl tracking-tight text-white">ThinkFlow</span>
            </div>
            <div className="flex bg-slate-900/50 backdrop-blur rounded-full p-1 border border-white/5">
              {(['ru', 'en', 'uz'] as const).map((lang) => (
                <button
                  key={lang}
                  onClick={() => setTempLang(lang)}
                  className={`px-4 py-1.5 rounded-full text-xs font-black transition-all ${
                    tempLang === lang 
                      ? 'bg-white text-slate-900 shadow-xl' 
                      : 'text-slate-400 hover:text-white'
                  }`}
                >
                  {lang.toUpperCase()}
                </button>
              ))}
            </div>
          </header>

          <div className="max-w-4xl w-full text-center space-y-12 animate-in fade-in zoom-in duration-700">
            <div className="space-y-4">
              <h1 className="text-6xl md:text-8xl font-extrabold tracking-tight leading-none">
                <span className="text-white">Learn With </span>
                <span className="text-gradient">Precision.</span>
              </h1>
              <p className="text-xl text-slate-400 max-w-2xl mx-auto leading-relaxed">
                {t.heroSub}
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="glass p-8 rounded-3xl text-left border-indigo-500/20 group hover:border-indigo-500/50 transition-colors">
                <div className="w-12 h-12 bg-blue-500/20 rounded-2xl flex items-center justify-center text-blue-400 mb-6 text-2xl group-hover:scale-110 transition-transform">🧠</div>
                <h3 className="font-bold text-lg mb-2">{t.teacher}</h3>
                <p className="text-sm text-slate-400 leading-relaxed">Complex concepts explained through your personal hobbies and interests.</p>
              </div>
              <div className="glass p-8 rounded-3xl text-left border-purple-500/20 group hover:border-purple-500/50 transition-colors">
                <div className="w-12 h-12 bg-purple-500/20 rounded-2xl flex items-center justify-center text-purple-400 mb-6 text-2xl group-hover:scale-110 transition-transform">🔍</div>
                <h3 className="font-bold text-lg mb-2">{t.coach}</h3>
                <p className="text-sm text-slate-400 leading-relaxed">A Socratic guide that asks the right questions to make you think, not just solve.</p>
              </div>
              <div className="glass p-8 rounded-3xl text-left border-pink-500/20 group hover:border-pink-500/50 transition-colors">
                <div className="w-12 h-12 bg-pink-500/20 rounded-2xl flex items-center justify-center text-pink-400 mb-6 text-2xl group-hover:scale-110 transition-transform">⚡</div>
                <h3 className="font-bold text-lg mb-2">{t.trainer}</h3>
                <p className="text-sm text-slate-400 leading-relaxed">Adaptive challenges that evolve with your performance and class level.</p>
              </div>
            </div>

            <div className="flex flex-col md:flex-row gap-4 justify-center items-center pb-12">
              <button onClick={() => setAuthMode('register')} className="btn-gradient px-12 py-4 rounded-2xl font-bold text-white shadow-xl w-full md:w-auto text-lg">
                {t.register}
              </button>
              <button onClick={() => setAuthMode('login')} className="px-12 py-4 rounded-2xl font-bold glass hover:bg-white/10 transition-all w-full md:w-auto text-lg text-slate-300">
                {t.login}
              </button>
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="min-h-screen bg-main-gradient flex items-center justify-center p-4">
        <form onSubmit={handleAuth} className="glass p-10 rounded-3xl max-w-lg w-full shadow-2xl space-y-6 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 shimmer pointer-events-none" />
          <h2 className="text-3xl font-extrabold text-center text-gradient">
            {authMode === 'register' ? t.register : t.login}
          </h2>

          <div className="space-y-4">
            <div className="grid grid-cols-1 gap-4">
              {authMode === 'register' && (
                <input name="name" placeholder="Full Name" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm focus:ring-2 ring-indigo-500 outline-none" />
              )}
              <input name="email" type="email" placeholder="Email" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm focus:ring-2 ring-indigo-500 outline-none" />
              <input name="password" type="password" placeholder="Password" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm focus:ring-2 ring-indigo-500 outline-none" />
            </div>

            {authMode === 'register' && (
              <>
                <div className="flex gap-4">
                  <select name="class" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm flex-1 outline-none appearance-none">
                    {CLASSES.map(c => <option key={c} value={c} className="bg-slate-900">{c}</option>)}
                  </select>
                  <select name="language" required className="bg-slate-900/50 border border-slate-700/50 rounded-xl p-3 text-sm flex-1 outline-none appearance-none">
                    <option value="en" className="bg-slate-900">English</option>
                    <option value="ru" className="bg-slate-900">Русский</option>
                    <option value="uz" className="bg-slate-900">O'zbekcha</option>
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Select Interests</label>
                  <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto p-2 bg-slate-950/50 rounded-xl border border-slate-700/50">
                    {INTERESTS_POOL.map(i => (
                      <label key={i} className="flex items-center gap-1 bg-slate-800/80 px-2.5 py-1.5 rounded-lg text-[10px] cursor-pointer hover:bg-indigo-500/20 transition-all border border-transparent peer-checked:border-indigo-500">
                        <input type="checkbox" name={`interest-${i}`} className="hidden peer" />
                        <span className="peer-checked:text-indigo-400 font-bold">{i}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>

          <button type="submit" className="w-full btn-gradient py-4 rounded-xl font-black text-sm uppercase tracking-widest shadow-lg">
            {authMode === 'register' ? t.register : t.login}
          </button>

          <button type="button" onClick={() => setAuthMode(authMode === 'register' ? 'login' : 'register')} className="w-full text-slate-500 text-xs hover:text-indigo-400 transition-colors">
            {authMode === 'register' ? t.hasAccount : t.noAccount}
          </button>

          <button type="button" onClick={() => setAuthMode('landing')} className="w-full text-slate-600 text-[10px] mt-4">← Back to Home</button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex overflow-hidden">
      <nav className="w-64 bg-slate-900/40 backdrop-blur-xl border-r border-slate-800/50 flex flex-col p-6 space-y-10 relative z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 btn-gradient rounded-xl flex items-center justify-center font-black text-xl italic shadow-lg">T</div>
          <div>
            <h2 className="font-black text-lg tracking-tight">ThinkFlow</h2>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest">Personal Workspace</p>
          </div>
        </div>

        <div className="space-y-3">
          <NavItem icon="⚡" label={t.learn} active={view === 'learn'} onClick={() => setView('learn')} />
          <NavItem icon="🎯" label={t.tasks} active={view === 'tasks'} onClick={() => setView('tasks')} />
          <NavItem icon="🎖️" label={t.leaderboard} active={view === 'leaderboard'} onClick={() => setView('leaderboard')} />
          <NavItem icon="✨" label={t.profile} active={view === 'profile'} onClick={() => setView('profile')} />
          {user.isAdmin && <NavItem icon="🛡️" label={t.admin} active={view === 'admin'} onClick={() => setView('admin')} />}
        </div>

        <div className="mt-auto glass p-5 rounded-2xl border-indigo-500/10 space-y-4">
          <div className="flex justify-between items-end">
            <div>
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">{t.level}</p>
              <p className="text-2xl font-black text-indigo-400 leading-none">{user.level}</p>
            </div>
            <div className="text-right">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">{t.xp}</p>
              <p className="text-xs font-bold text-white">{user.xp}</p>
            </div>
          </div>
          <div className="w-full h-2 bg-slate-800 rounded-full overflow-hidden">
            <div className="h-full btn-gradient" style={{ width: `${user.xp % 100}%` }} />
          </div>
          <p className="text-[10px] text-slate-400 text-center font-bold truncate">{user.name}</p>
        </div>
      </nav>

      <main className="flex-1 flex flex-col bg-slate-950">
        <header className="h-20 border-b border-slate-800/50 flex items-center justify-between px-10 bg-slate-950/50 backdrop-blur-md">
          <h2 className="text-xl font-black uppercase tracking-widest text-slate-400">{view}</h2>
          <div className="flex items-center gap-4">
            <div className="px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-[10px] font-black uppercase tracking-widest">
              {user.studentClass} SEC
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 relative">
          <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-600/5 blur-[120px] rounded-full pointer-events-none" />

          {view === 'learn' && (
            <div className="max-w-4xl mx-auto flex flex-col h-full space-y-8 animate-in slide-in-from-bottom duration-500">
              <div className="flex gap-4 justify-center">
                <RoleBtn active={activeRole === 'teacher'} label={t.teacher} onClick={() => setActiveRole('teacher')} color="btn-gradient" />
                <RoleBtn active={activeRole === 'coach'} label={t.coach} onClick={() => setActiveRole('coach')} color="bg-amber-500 shadow-amber-500/20" />
                <RoleBtn active={activeRole === 'trainer'} label={t.trainer} onClick={() => setActiveRole('trainer')} color="bg-emerald-500 shadow-emerald-500/20" />
              </div>

              <div className="flex-1 glass rounded-3xl p-8 overflow-y-auto space-y-6 flex flex-col border-slate-800/50 shadow-inner">
                {messages.length === 0 && (
                  <div className="flex-1 flex flex-col items-center justify-center text-slate-600 text-center space-y-4">
                    <div className="w-20 h-20 bg-indigo-500/5 rounded-full flex items-center justify-center text-5xl">🔭</div>
                    <p className="font-bold text-lg text-slate-200">{t.welcome}, {user.name}!</p>
                    <p className="text-sm max-w-xs">{t.heroSub}</p>
                  </div>
                )}
                {messages.map((m, i) => (
                  <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[75%] rounded-3xl p-5 text-sm leading-relaxed ${m.role === 'user' ? 'btn-gradient font-bold shadow-lg' : 'glass border-slate-700/50'}`}>
                      {m.text}
                    </div>
                  </div>
                ))}
                {isLoading && <div className="text-[10px] text-indigo-400 font-black animate-pulse uppercase tracking-[0.2em]">Processing insight...</div>}
              </div>

              <div className="flex gap-3">
                <input 
                  value={input}
                  onChange={e => setInput(e.target.value)}
                  onKeyPress={e => e.key === 'Enter' && handleSendMessage()}
                  placeholder={t.startThinking}
                  className="flex-1 bg-slate-900 border border-slate-800/50 rounded-2xl px-6 py-4 outline-none focus:ring-2 ring-indigo-500 transition-all font-medium placeholder:text-slate-700 text-white"
                />
                <button onClick={handleSendMessage} className="btn-gradient px-8 rounded-2xl font-black uppercase text-xs tracking-widest text-white shadow-lg">Submit</button>
              </div>
            </div>
          )}

          {view === 'tasks' && (
            <div className="max-w-2xl mx-auto space-y-10 py-10 animate-in slide-in-from-right duration-500">
              {!currentTask ? (
                <div className="text-center space-y-8 glass p-12 rounded-[40px] border-emerald-500/10">
                  <div className="w-24 h-24 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto text-5xl">🐉</div>
                  <h3 className="text-3xl font-black tracking-tight">Adaptive Mission Control</h3>
                  <p className="text-slate-400 italic">"Personalized challenges generated based on your progress."</p>
                  <button onClick={getNewTask} disabled={isLoading} className="bg-emerald-600 hover:bg-emerald-500 px-12 py-4 rounded-2xl font-black text-white shadow-xl shadow-emerald-500/20 transition-all disabled:opacity-50">
                    {isLoading ? 'Synthesizing...' : t.trainBrain}
                  </button>
                </div>
              ) : (
                <div className="glass border-2 border-emerald-500/30 rounded-[40px] p-10 space-y-6 relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 blur-[50px]" />
                  <div className="flex justify-between items-center">
                    <span className="px-4 py-1 bg-emerald-500/20 text-emerald-400 rounded-full text-[10px] uppercase font-black tracking-widest">{currentTask.difficulty}</span>
                    <span className="text-indigo-400 font-black">+{currentTask.xpReward} XP</span>
                  </div>
                  <h3 className="text-3xl font-black leading-tight tracking-tight">{currentTask.title}</h3>
                  <p className="text-slate-400 leading-relaxed text-lg">{currentTask.description}</p>
                  <div className="pt-6 flex gap-4">
                    <button onClick={() => { setActiveRole('trainer'); setView('learn'); }} className="flex-1 btn-gradient py-4 rounded-2xl font-black uppercase text-xs tracking-widest text-white">Accept Mission</button>
                    <button onClick={() => setCurrentTask(null)} className="px-6 py-4 glass rounded-2xl text-xs font-bold text-slate-500">Refresh</button>
                  </div>
                </div>
              )}
            </div>
          )}

          {view === 'leaderboard' && (
            <div className="max-w-3xl mx-auto space-y-6 py-6 animate-in zoom-in duration-500">
              <h3 className="text-3xl font-black tracking-tight mb-8">Global Hall of Fame</h3>
              {allStudents.length === 0 ? (
                 <div className="glass p-12 rounded-3xl text-center text-slate-500">No students yet. Join the ranks!</div>
              ) : allStudents.sort((a, b) => b.xp - a.xp).map((student, i) => (
                <div key={i} className={`flex items-center justify-between p-6 rounded-3xl border transition-all ${student.email === user.email ? 'bg-indigo-600/20 border-indigo-500/50 shadow-lg shadow-indigo-500/10' : 'glass border-slate-800/50 hover:border-slate-700'}`}>
                  <div className="flex items-center gap-6">
                    <span className={`font-black text-2xl w-8 text-center ${i < 3 ? 'text-indigo-400' : 'text-slate-600'}`}>#{i+1}</span>
                    <div className="w-14 h-14 btn-gradient rounded-2xl flex items-center justify-center font-black text-xl shadow-md">{student.name[0]}</div>
                    <div>
                      <p className="font-extrabold text-lg">{student.name}</p>
                      <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{student.studentClass} Class • Lvl {student.level}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <span className="font-mono font-black text-xl text-indigo-400 tracking-tighter">{student.xp}</span>
                    <p className="text-[8px] text-slate-600 font-black uppercase">Points</p>
                  </div>
                </div>
              ))}
            </div>
          )}

          {view === 'profile' && (
            <div className="max-w-2xl mx-auto glass border-slate-800/50 rounded-[40px] p-12 space-y-12 animate-in fade-in duration-700 relative overflow-hidden">
              <div className="absolute -top-24 -left-24 w-64 h-64 bg-indigo-500/10 blur-[80px] rounded-full" />
              <div className="flex items-center gap-8 relative z-10">
                <div className="w-32 h-32 btn-gradient rounded-[32px] flex items-center justify-center text-5xl font-black shadow-2xl">{user.name[0]}</div>
                <div className="space-y-2">
                  <h3 className="text-4xl font-black tracking-tight leading-none text-white">{user.name}</h3>
                  <p className="text-slate-500 font-medium">{user.email}</p>
                  <div className="flex gap-2 pt-2">
                    <span className="px-4 py-1 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-[10px] font-black tracking-widest text-indigo-400">{user.studentClass} SEC</span>
