        interests: interests.length > 0 ? interests : ['Science'],
        xp: 0,
        level: 1,
        isAdmin: email.toLowerCase() === ADMIN_EMAIL.toLowerCase()
      };
      setUser(newUser);
      setAllStudents(prev => [...prev.filter(s => s.email !== newUser.email), newUser]);
    } else {
      const found = allStudents.find(s => s.email === email);
      if (found) {
        // Update admin status on login just in case
