                <button
                  key={lang}
                  onClick={() => setTempLang(lang)}
                  className={`px-4 py-1.5 rounded-lg text-[10px] font-black tracking-widest transition-all ${
                    tempLang === lang 
                      ? 'bg-indigo-600 text-white' 
                      : 'text-slate-400 hover:text-white'
                  }`}
                >
                  {lang.toUpperCase()}
                </button>
              ))}
            </div>
          </header>

          <div className="max-w-4xl w-full text-center space-y-16 animate-in fade-in duration-700">
            <div className="space-y-6">
              <h1 className="text-6xl md:text-8xl font-black tracking-tighter leading-none text-white">
                Think with <br/><span className="text-gradient">Precision.</span>
              </h1>
              <p className="text-lg text-slate-400 max-w-2xl mx-auto font-medium leading-relaxed">
                {t.heroSub}
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
               <div className="glass p-8 rounded-3xl border-white/5 flex flex-col items-center">
                 <div className="text-3xl mb-4">🧠</div>
                 <h4 className="text-indigo-400 font-black uppercase text-xs tracking-widest mb-2">{t.teacher}</h4>
                 <p className="text-[11px] text-slate-500">{t.roleDescTeacher}</p>
               </div>
               <div className="glass p-8 rounded-3xl border-white/5 flex flex-col items-center">
                 <div className="text-3xl mb-4">🔍</div>
                 <h4 className="text-purple-400 font-black uppercase text-xs tracking-widest mb-2">{t.coach}</h4>
                 <p className="text-[11px] text-slate-500">{t.roleDescCoach}</p>
               </div>
               <div className="glass p-8 rounded-3xl border-white/5 flex flex-col items-center">
                 <div className="text-3xl mb-4">⚡</div>
                 <h4 className="text-indigo-500 font-black uppercase text-xs tracking-widest mb-2">{t.trainer}</h4>
                 <p className="text-[11px] text-slate-500">{t.roleDescTrainer}</p>
               </div>
            </div>

            <div className="flex flex-col md:flex-row gap-6 justify-center items-center pb-20">
              <button onClick={() => setAuthMode('register')} className="btn-gradient px-16 py-5 rounded-2xl font-black uppercase text-sm tracking-widest shadow-2xl w-full md:w-auto">
                {t.register}
              </button>
              <button onClick={() => setAuthMode('login')} className="px-16 py-5 rounded-2xl font-black uppercase text-sm tracking-widest border border-white/10 hover:bg-white/5 transition-all w-full md:w-auto text-slate-400">
                {t.login}
              </button>
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="min-h-screen bg-main-gradient flex items-center justify-center p-4">
        <form onSubmit={handleAuth} className="glass p-12 rounded-3xl max-w-lg w-full shadow-2xl space-y-8 relative overflow-hidden border-indigo-500/10">
          <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500/20 shimmer" />
          <h2 className="text-3xl font-black text-center text-white tracking-tighter uppercase">
            {authMode === 'register' ? t.register : t.login}
          </h2>

          <div className="space-y-4">
            <div className="grid grid-cols-1 gap-4">
              {authMode === 'register' && (
                <input name="name" placeholder="Full Name" required className="bg-slate-900/80 border border-white/5 rounded-xl p-4 text-sm focus:border-indigo-500 outline-none transition-colors text-white" />
              )}
              <input name="email" type="email" placeholder="Email Address" required className="bg-slate-900/80 border border-white/5 rounded-xl p-4 text-sm focus:border-indigo-500 outline-none transition-colors text-white" />
              <input name="password" type="password" placeholder="Password" required className="bg-slate-900/80 border border-white/5 rounded-xl p-4 text-sm focus:border-indigo-500 outline-none transition-colors text-white" />
            </div>

            {authMode === 'register' && (
              <>
                <div className="flex gap-4">
                  <select name="class" required className="bg-slate-900/80 border border-white/5 rounded-xl p-4 text-sm flex-1 outline-none text-slate-400">
                    {CLASSES.map(c => <option key={c} value={c} className="bg-slate-900">{c}</option>)}
