                  <select name="language" required className="bg-slate-900/80 border border-white/5 rounded-xl p-4 text-sm flex-1 outline-none text-slate-400">
                    <option value="en" className="bg-slate-900">EN</option>
                    <option value="ru" className="bg-slate-900">RU</option>
                    <option value="uz" className="bg-slate-900">UZ</option>
                  </select>
                </div>

                <div className="space-y-3">
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Knowledge Nodes</p>
                  <div className="flex flex-wrap gap-2 max-h-32 overflow-y-auto p-3 bg-slate-950/50 rounded-xl border border-white/5">
                    {INTERESTS_POOL.map(i => (
