          </div>
        </div>

        <div className="space-y-4">
          <NavItem icon="⚡" label={t.learn} active={view === 'learn'} onClick={() => setView('learn')} />
          <NavItem icon="🎯" label={t.tasks} active={view === 'tasks'} onClick={() => setView('tasks')} />
          <NavItem icon="🎖️" label={t.leaderboard} active={view === 'leaderboard'} onClick={() => setView('leaderboard')} />
          <NavItem icon="✨" label={t.profile} active={view === 'profile'} onClick={() => setView('profile')} />
          {user.isAdmin && <NavItem icon="🛡️" label={t.admin} active={view === 'admin'} onClick={() => setView('admin')} />}
        </div>

        <div className="mt-auto glass p-6 rounded-2xl border-indigo-500/10 space-y-4">
          <div className="flex justify-between items-end">
            <div className="space-y-1">
              <p className="text-[8px] text-slate-500 uppercase font-black tracking-widest">Rank</p>
              <p className="text-3xl font-black text-white leading-none tracking-tighter">{user.level}</p>
            </div>
            <div className="text-right">
              <p className="text-[8px] text-slate-500 uppercase font-black tracking-widest">XP</p>
              <p className="text-sm font-black text-indigo-400">{user.xp}</p>
