                <div className="flex flex-wrap gap-2">
                  {user.interests.map(i => <span key={i} className="px-4 py-2 bg-indigo-500/10 rounded-xl text-[10px] font-black text-indigo-400 uppercase tracking-widest border border-indigo-500/20">{i}</span>)}
                </div>
              </div>
              <button onClick={() => { localStorage.clear(); window.location.reload(); }} className="w-full text-slate-800 text-[10px] font-black uppercase tracking-[0.4em] hover:text-red-500 transition-colors">Sign Out</button>
            </div>
          )}

          {view === 'admin' && user.isAdmin && (
            <div className="max-w-5xl mx-auto space-y-8 py-4 animate-in fade-in">
               <h3 className="text-3xl font-black tracking-tighter uppercase text-white">Command Center</h3>
               <div className="glass border-white/10 rounded-[2.5rem] overflow-hidden shadow-2xl">
                 <table className="w-full text-left">
                   <thead className="bg-slate-900/50 text-slate-500 text-[10px] uppercase font-black tracking-[0.3em]">
                     <tr>
                       <th className="p-8">Entity</th>
                       <th className="p-8">Registry ID</th>
                       <th className="p-8">Sector</th>
                       <th className="p-8">Action</th>
                     </tr>
                   </thead>
                   <tbody className="text-sm">
                     {allStudents.map(student => (
                       <tr key={student.email} className="border-t border-white/5 hover:bg-white/[0.02] transition-colors">
                         <td className="p-8 font-black text-white uppercase tracking-tight">{student.name}</td>
                         <td className="p-8 text-slate-500 font-mono text-xs">{student.email}</td>
                         <td className="p-8 font-black text-indigo-400 uppercase tracking-widest">{student.studentClass}</td>
                         <td className="p-8">
                           <button 
                             onClick={() => setAllStudents(prev => prev.filter(s => s.email !== student.email))}
                             className="text-red-500/50 hover:text-red-500 font-black text-[10px] uppercase tracking-widest transition-all"
                           >
                             Purge
                           </button>
                         </td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon, label, active, onClick }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-5 rounded-2xl transition-all ${active ? 'nav-active font-black' : 'text-slate-600 hover:text-slate-300 hover:bg-white/5'}`}>
    <span className="text-xl">{icon}</span>
    <span className="font-black text-[10px] uppercase tracking-[0.3em]">{label}</span>
  </button>
);

const RoleSelectorBtn = ({ active, label, onClick }: any) => (
  <button 
