    className={`px-10 py-4 rounded-full text-[11px] font-black uppercase tracking-[0.2em] transition-all border-2 ${
      active 
        ? 'btn-gradient border-transparent shadow-[0_0_25px_rgba(163,85,247,0.3)]' 
        : 'bg-transparent text-slate-700 border-slate-900 hover:border-slate-800'
