const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [authMode, setAuthMode] = useState<'landing' | 'login' | 'register'>('landing');
  const [view, setView] = useState<'dashboard' | 'teacher' | 'coach' | 'tasks' | 'leaderboard' | 'profile' | 'admin'>('dashboard');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [allStudents, setAllStudents] = useState<UserProfile[]>([]);
  const [currentTask, setCurrentTask] = useState<Task | null>(null);
  const [tempLang, setTempLang] = useState<Language>('ru');
  const [reviews, setReviews] = useState<{name: string, text: string, rating: number}[]>([]);
  const [reviewInput, setReviewInput] = useState('');
  const [reviewRating, setReviewRating] = useState(5);

  useEffect(() => {
    const savedUser = localStorage.getItem('thinkflow_user');
    const savedStudents = localStorage.getItem('thinkflow_all_students');
    const savedReviews = localStorage.getItem('thinkflow_reviews');
    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedStudents) setAllStudents(JSON.parse(savedStudents));
    if (savedReviews) setReviews(JSON.parse(savedReviews));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('thinkflow_user', JSON.stringify(user));
    if (allStudents.length > 0) localStorage.setItem('thinkflow_all_students', JSON.stringify(allStudents));
    localStorage.setItem('thinkflow_reviews', JSON.stringify(reviews));
  }, [user, allStudents, reviews]);

  const t = useMemo(() => TRANSLATIONS[user?.language || tempLang], [user, tempLang]);

  const handleAuth = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const email = (formData.get('email') as string).toLowerCase().trim();
    const isAdminEmail = email === ADMIN_EMAIL.toLowerCase().trim();

    if (authMode === 'register') {
      const interests = INTERESTS_POOL.filter(i => formData.get(`interest-${i}`));
      const newUser: UserProfile = {
        email,
        name: formData.get('name') as string,
        studentClass: formData.get('class') as StudentClass,
        language: formData.get('language') as Language,
        interests: interests.length > 0 ? interests : ['Science'],
        xp: 0,
        level: 1,
        isAdmin: isAdminEmail
      };
      setUser(newUser);
      setAllStudents(prev => [...prev.filter(s => s.email !== newUser.email), newUser]);
    } else {
      const found = allStudents.find(s => s.email.toLowerCase() === email);
      if (found) {
        setUser({ ...found, isAdmin: isAdminEmail, studentClass: isAdminEmail ? '9B' : found.studentClass });
      } else if (isAdminEmail) {
         const adminUser: UserProfile = {
            email: ADMIN_EMAIL, name: "Sarvar (Admin)", studentClass: '9B', language: 'ru', interests: ['Coding'], xp: 9999, level: 100, isAdmin: true
         };
         setUser(adminUser);
         setAllStudents(prev => [...prev.filter(s => s.email !== adminUser.email), adminUser]);
      } else {
        alert("Account not found. Please register.");
        setAuthMode('register');
      }
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || !user) return;
    const userMsg: Message = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const role: 'teacher' | 'coach' | 'trainer' = view === 'teacher' ? 'teacher' : (view === 'tasks' ? 'trainer' : 'coach');

    try {
      const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const response = await askAI(role, input, user, history);
      const aiMsg: Message = { role: 'model', text: response || '', timestamp: Date.now() };
      setMessages(prev => [...prev, aiMsg]);
      const newXp = user.xp + 15;
      setUser({ ...user, xp: newXp, level: Math.floor(newXp / 100) + 1 });
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const submitReview = () => {
    if (!reviewInput.trim() || !user) return;
    const newReview = { name: user.name, text: reviewInput, rating: reviewRating };
    setReviews([newReview, ...reviews]);
    setReviewInput('');
    setReviewRating(5);
  };

  const getNewTask = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      const task = await generateAdaptiveTask(user);
      setCurrentTask(task);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  if (!user) {
    if (authMode === 'landing') {
      return (
        <div className="min-h-screen bg-[#020204] flex flex-col items-center p-6 text-slate-100 overflow-y-auto">
          <header className="w-full max-w-6xl flex justify-between items-center py-8 mb-16 border-b border-white/5">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-[#3b82f6] rounded-xl flex items-center justify-center font-black text-white shadow-lg shadow-blue-500/20">C</div>
              <span className="font-bold text-2xl tracking-tighter">Switcher</span>
            </div>
            <div className="flex bg-[#0f172a] rounded-lg p-1 border border-white/5">
              {(['ru', 'en', 'uz'] as const).map((lang) => (
                <button key={lang} onClick={() => setTempLang(lang)} className={`px-4 py-1 rounded-md text-[10px] font-bold tracking-widest ${tempLang === lang ? 'bg-[#3b82f6] text-white' : 'text-slate-400'}`}>
                  {lang.toUpperCase()}
                </button>
              ))}
            </div>
          </header>
          <div className="max-w-4xl w-full text-center space-y-12 animate-in fade-in duration-700 mt-20">
            <h1 className="text-6xl md:text-8xl font-extrabold tracking-tighter leading-tight">Think beyond <br/><span className="text-indigo-500">Limits.</span></h1>
            <p className="text-xl text-slate-400 max-w-2xl mx-auto font-medium">{t.heroSub}</p>
            <div className="flex flex-col md:flex-row gap-6 justify-center pt-8">
              <button onClick={() => setAuthMode('register')} className="bg-[#6366f1] px-12 py-4 rounded-xl font-bold uppercase tracking-widest hover:brightness-110 transition-all shadow-xl">{t.register}</button>
              <button onClick={() => setAuthMode('login')} className="bg-transparent border border-white/10 px-12 py-4 rounded-xl font-bold uppercase tracking-widest hover:bg-white/5 transition-all text-slate-300">{t.login}</button>
            </div>
          </div>
        </div>
      );
    }
    return (
      <div className="min-h-screen bg-[#020204] flex items-center justify-center p-4 text-slate-100">
        <form onSubmit={handleAuth} className="glass p-12 rounded-[2rem] max-w-lg w-full shadow-2xl space-y-8 border-indigo-500/10">
          <h2 className="text-3xl font-black text-center uppercase tracking-tight">{authMode === 'register' ? t.register : t.login}</h2>
          <div className="space-y-4">
            {authMode === 'register' && <input name="name" placeholder="Name" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-xl p-4 text-sm focus:border-indigo-500 outline-none text-white" />}
            <input name="email" type="email" placeholder="Email" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-xl p-4 text-sm focus:border-indigo-500 outline-none text-white" />
            <input name="password" type="password" placeholder="Password" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-xl p-4 text-sm focus:border-indigo-500 outline-none text-white" />
            {authMode === 'register' && (
              <div className="flex gap-4">
                <select name="class" className="flex-1 bg-[#0a0a0b] border border-white/5 rounded-xl p-4 text-sm text-slate-400">
                  {CLASSES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <select name="language" className="flex-1 bg-[#0a0a0b] border border-white/5 rounded-xl p-4 text-sm text-slate-400">
                  <option value="ru">RU</option>
                  <option value="en">EN</option>
                  <option value="uz">UZ</option>
                </select>
              </div>
            )}
          </div>
          <button type="submit" className="w-full bg-[#6366f1] py-4 rounded-xl font-bold uppercase tracking-widest shadow-xl">{authMode === 'register' ? 'Join' : 'Enter'}</button>
          <button type="button" onClick={() => setAuthMode(authMode === 'register' ? 'login' : 'register')} className="w-full text-slate-500 text-[10px] font-bold uppercase tracking-widest hover:text-indigo-400">
            {authMode === 'register' ? 'Login instead' : 'Register instead'}
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-[#020204] text-slate-100 overflow-hidden font-sans">
      <nav className="w-64 bg-[#0a0a0b] flex flex-col py-6 border-r border-white/5">
        <div className="px-6 mb-10 flex items-center gap-2">
          <div className="w-8 h-8 bg-[#3b82f6] rounded-md flex items-center justify-center font-bold text-lg text-white">C</div>
          <span className="font-bold text-lg tracking-tight">Switcher</span>
        </div>

        <div className="flex-1 flex flex-col gap-1 px-4">
          <SideItem icon="grid" label={t.dashboard} active={view === 'dashboard'} onClick={() => setView('dashboard')} />
          <SideItem icon="lightbulb" label={t.conceptTeacher} active={view === 'teacher'} onClick={() => { setView('teacher'); setMessages([]); }} />
          <SideItem icon="brain" label={t.thinkingCoach} active={view === 'coach'} onClick={() => { setView('coach'); setMessages([]); }} />
          <SideItem icon="tasks" label={t.adaptiveTasks} active={view === 'tasks'} onClick={() => setView('tasks')} />
          <SideItem icon="trophy" label={t.wallOfFame} active={view === 'leaderboard'} onClick={() => setView('leaderboard')} />
          <SideItem icon="chat" label={t.community} active={false} onClick={() => {}} />
          <SideItem icon="user" label={t.myProfile} active={view === 'profile'} onClick={() => setView('profile')} />
          {user.isAdmin && <SideItem icon="shield" label={t.admin} active={view === 'admin'} onClick={() => setView('admin')} />}
        </div>

        <div className="px-4 mt-auto">
          <div className="bg-[#121214] p-4 rounded-xl flex items-center gap-3 border border-white/5">
            <div className="w-10 h-10 bg-indigo-500/20 rounded-full flex items-center justify-center text-indigo-400 font-bold">{user.name[0]}</div>
            <div className="overflow-hidden">
              <p className="font-bold text-sm truncate">{user.name}</p>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">GRADE {user.studentClass}</p>
            </div>
            <div className="ml-auto w-2 h-2 bg-green-500 rounded-full shadow-[0_0_8px_rgba(34,197,94,0.5)]"></div>
          </div>
        </div>
      </nav>

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {(view === 'teacher' || view === 'coach') && (
          <div className="flex-1 flex flex-col p-12 max-w-5xl mx-auto w-full animate-in fade-in duration-500">
            <div className="mb-10 space-y-1">
              <div className="flex items-center gap-3">
                <span className="text-3xl text-indigo-500">
                  {view === 'teacher' ? (
                    <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" /></svg>
                  ) : (
                    <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm.88 15.76V19h-1.75v-1.24c-1.28-.17-2.42-.81-3.23-1.72l1.25-1.25c.5.54 1.2.93 1.98 1.05v-2.09c-1.48-.35-2.63-1.32-2.63-3.13 0-1.8 1.15-2.78 2.63-3.13V6.25h1.75V7.5c1.28.17 2.42.81 3.23 1.72l-1.25 1.25c-.5-.54-1.2-.93-1.98-1.05v2.09c1.48.35 2.63 1.32 2.63 3.13 0 1.8-1.15 2.78-2.63 3.13z" /></svg>
                  )}
                </span>
                <h2 className="text-3xl font-bold tracking-tight text-white">{view === 'teacher' ? t.conceptTeacher : t.thinkingCoach}</h2>
              </div>
              <p className="text-slate-500 font-medium ml-11">{view === 'teacher' ? t.teacherDesc : t.coachDesc}</p>
            </div>

            <div className="flex-1 overflow-y-auto mb-20 pr-4 custom-scrollbar space-y-6">
              {messages.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-40 space-y-4">
                  <div className="w-20 h-20 bg-white/5 rounded-2xl flex items-center justify-center text-4xl">
                    <svg className="w-12 h-12 text-slate-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" /></svg>
                  </div>
                  <p className="text-xl font-medium">{t.pasteProblem}</p>
                </div>
              ) : (
                messages.map((m, i) => (
                  <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[75%] p-5 rounded-2xl text-[15px] leading-relaxed shadow-lg ${m.role === 'user' ? 'bg-[#1a1a1c] border border-white/5' : 'bg-[#1a1a1c] border border-white/5 text-slate-200'}`}>
                      {m.text}
                    </div>
                  </div>
                ))
              )}
              {isLoading && <div className="text-[10px] text-indigo-400 font-bold animate-pulse uppercase tracking-[0.3em] ml-2">Synthesizing flow...</div>}
            </div>

            <div className="absolute bottom-8 left-[calc(50%+32px)] -translate-x-1/2 w-full max-w-2xl px-6">
              <div className="bg-[#121214] border border-white/10 rounded-2xl p-2 flex items-center shadow-2xl">
                <input 
                  value={input}
                  onChange={e => setInput(e.target.value)}
                  onKeyPress={e => e.key === 'Enter' && handleSendMessage()}
                  placeholder={t.startThinking}
                  className="flex-1 bg-transparent px-6 py-4 outline-none font-medium placeholder:text-slate-600 text-[15px]"
                />
                <button 
                  onClick={handleSendMessage}
                  className="w-11 h-11 bg-[#4f46e5] hover:bg-indigo-600 rounded-xl flex items-center justify-center transition-all text-white shadow-lg"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                  </svg>
                </button>
              </div>
            </div>
          </div>
        )}

        {view === 'dashboard' && (
          <div className="flex-1 p-12 max-w-5xl mx-auto w-full space-y-12 overflow-y-auto custom-scrollbar">
            <h2 className="text-4xl font-extrabold tracking-tight">System <span className="text-indigo-500">Registry</span></h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <DashboardCard label="Active Rank" value={`Level ${user.level}`} icon="⚡" />
              <DashboardCard label="Cognitive XP" value={`${user.xp}`} icon="💎" />
            </div>

            {/* Inspiration Quote */}
            <div className="bg-[#1a1a1c]/40 border border-white/5 p-10 rounded-3xl text-center space-y-4">
               <p className="text-[10px] text-slate-500 font-black uppercase tracking-[0.4em]">{t.quotes}</p>
               <p className="text-2xl font-bold italic tracking-tight text-white">"{QUOTES[Math.floor(Date.now()/86400000) % QUOTES.length].text}"</p>
               <p className="text-xs text-indigo-400 font-bold">— {QUOTES[Math.floor(Date.now()/86400000) % QUOTES.length].author}</p>
            </div>

            {/* Knowledge Base Articles */}
            <div className="space-y-6">
               <h3 className="text-xl font-bold uppercase tracking-widest text-slate-400 flex items-center gap-3">
                 <span className="w-6 h-0.5 bg-indigo-500"></span>{t.articles}
               </h3>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {ARTICLES.map(art => (
                    <div key={art.id} className="bg-[#0a0a0b] p-8 rounded-3xl border border-white/5 hover:border-indigo-500/30 transition-all group">
                       <div className="text-3xl mb-4 group-hover:scale-110 transition-transform">{art.icon}</div>
                       <p className="text-[9px] text-indigo-500 font-bold uppercase tracking-widest mb-2">{art.category}</p>
                       <h4 className="text-lg font-bold text-white mb-3">{art.title}</h4>
                       <p className="text-xs text-slate-400 leading-relaxed line-clamp-3">{art.content}</p>
                    </div>
                  ))}
               </div>
            </div>

            {/* Reviews Section */}
            <div className="space-y-8 bg-[#0a0a0b] p-10 rounded-[2.5rem] border border-white/5">
               <div className="flex justify-between items-center">
                 <h3 className="text-xl font-bold uppercase tracking-widest text-slate-400">{t.reviews}</h3>
               </div>

               <div className="space-y-4">
                  <div className="flex gap-4">
                    <input 
                      value={reviewInput}
                      onChange={e => setReviewInput(e.target.value)}
                      placeholder={t.writeReview}
                      className="flex-1 bg-[#121214] border border-white/10 rounded-xl px-6 py-4 outline-none text-sm"
                    />
                    <select 
                      value={reviewRating} 
                      onChange={e => setReviewRating(Number(e.target.value))}
                      className="bg-[#121214] border border-white/10 rounded-xl px-4 py-4 text-yellow-500 font-bold"
                    >
                      <option value="5">⭐⭐⭐⭐⭐</option>
                      <option value="4">⭐⭐⭐⭐</option>
                      <option value="3">⭐⭐⭐</option>
                      <option value="2">⭐⭐</option>
                      <option value="1">⭐</option>
                    </select>
                    <button onClick={submitReview} className="bg-indigo-600 px-8 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-indigo-500 transition-colors">
                      {t.submit}
