                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-6">
                     {reviews.length === 0 ? (
                       <p className="text-slate-600 text-xs italic">No reviews yet. Be the first!</p>
                     ) : (
                       reviews.map((rev, i) => (
                        <div key={i} className="bg-[#121214]/50 border border-white/5 p-6 rounded-2xl space-y-2">
                           <div className="flex justify-between items-start">
                             <p className="font-bold text-sm text-indigo-400">{rev.name}</p>
                             <div className="text-[10px] text-yellow-500">{'⭐'.repeat(rev.rating)}</div>
                           </div>
                           <p className="text-xs text-slate-300 italic">"{rev.text}"</p>
                        </div>
                       ))
                     )}
                  </div>
               </div>
            </div>
          </div>
        )}

        {view === 'tasks' && (
          <div className="flex-1 p-12 max-w-2xl mx-auto w-full text-center space-y-12">
            <h2 className="text-3xl font-bold tracking-tight">Mission Control</h2>
            <div className="glass p-16 rounded-[3rem] border-indigo-500/20 space-y-8">
