const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [authMode, setAuthMode] = useState<'landing' | 'login' | 'register'>('landing');
  const [view, setView] = useState<'dashboard' | 'teacher' | 'coach' | 'tasks' | 'leaderboard' | 'profile' | 'admin'>('dashboard');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [allStudents, setAllStudents] = useState<UserProfile[]>([]);
  const [currentTask, setCurrentTask] = useState<Task | null>(null);
  const [tempLang, setTempLang] = useState<Language>('ru');
  const [reviews, setReviews] = useState<{name: string, text: string, rating: number, date: number}[]>([]);
  const [reviewInput, setReviewInput] = useState('');
  const [reviewRating, setReviewRating] = useState(5);

  useEffect(() => {
    const savedUser = localStorage.getItem('thinkflow_user');
    const savedStudents = localStorage.getItem('thinkflow_all_students');
    const savedReviews = localStorage.getItem('thinkflow_reviews');
    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedStudents) setAllStudents(JSON.parse(savedStudents));
    if (savedReviews) setReviews(JSON.parse(savedReviews));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('thinkflow_user', JSON.stringify(user));
    if (allStudents.length > 0) localStorage.setItem('thinkflow_all_students', JSON.stringify(allStudents));
    localStorage.setItem('thinkflow_reviews', JSON.stringify(reviews));
  }, [user, allStudents, reviews]);

  const t = useMemo(() => TRANSLATIONS[user?.language || tempLang], [user, tempLang]);

  const handleAuth = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const email = (formData.get('email') as string).toLowerCase().trim();
    const isAdminEmail = email === ADMIN_EMAIL.toLowerCase().trim();

    if (authMode === 'register') {
      const interests = INTERESTS_POOL.filter(i => formData.get(`interest-${i}`));
      const newUser: UserProfile = {
        email,
        name: formData.get('name') as string,
        studentClass: (isAdminEmail ? '9B' : formData.get('class') as StudentClass),
        language: formData.get('language') as Language,
        interests: interests.length > 0 ? interests : ['Science'],
        xp: 0,
        level: 1,
        isAdmin: isAdminEmail
      };
      setUser(newUser);
      setAllStudents(prev => [...prev.filter(s => s.email !== newUser.email), newUser]);
    } else {
      const found = allStudents.find(s => s.email.toLowerCase() === email);
      if (found) {
        setUser({ ...found, isAdmin: isAdminEmail, studentClass: isAdminEmail ? '9B' : found.studentClass });
      } else if (isAdminEmail) {
         const adminUser: UserProfile = {
            email: ADMIN_EMAIL, name: "Sarvar (Admin)", studentClass: '9B', language: 'ru', interests: ['Coding'], xp: 9999, level: 100, isAdmin: true
         };
         setUser(adminUser);
         setAllStudents(prev => [...prev.filter(s => s.email !== adminUser.email), adminUser]);
      } else {
        alert("Account not found. Please register.");
        setAuthMode('register');
      }
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || !user) return;
    const userMsg: Message = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const role: 'teacher' | 'coach' | 'trainer' = view === 'teacher' ? 'teacher' : (view === 'tasks' ? 'trainer' : 'coach');

    try {
      const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const response = await askAI(role, input, user, history);
      const aiMsg: Message = { role: 'model', text: response || '', timestamp: Date.now() };
      setMessages(prev => [...prev, aiMsg]);
      const newXp = user.xp + 15;
      setUser({ ...user, xp: newXp, level: Math.floor(newXp / 100) + 1 });
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const submitReview = () => {
    if (!reviewInput.trim() || !user) return;
    const newReview = { 
      name: user.name, 
      text: reviewInput, 
      rating: reviewRating,
      date: Date.now()
    };
    setReviews([newReview, ...reviews]);
    setReviewInput('');
    setReviewRating(5);
  };

  const getNewTask = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
      const task = await generateAdaptiveTask(user);
      setCurrentTask(task);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  if (!user) {
    if (authMode === 'landing') {
      return (
        <div className="h-screen w-full bg-[#020204] flex flex-col items-center p-6 text-slate-100 overflow-y-auto custom-scrollbar">
          <header className="w-full max-w-6xl flex justify-between items-center py-8 mb-16 border-b border-white/5">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gradient-to-tr from-blue-600 to-indigo-500 rounded-xl flex items-center justify-center font-black text-white shadow-[0_0_20px_rgba(37,99,235,0.4)]">C</div>
              <span className="font-bold text-2xl tracking-tighter">Switcher</span>
            </div>
            <div className="flex bg-[#0f172a] rounded-lg p-1 border border-white/5">
              {(['ru', 'en', 'uz'] as const).map((lang) => (
                <button key={lang} onClick={() => setTempLang(lang)} className={`px-4 py-1 rounded-md text-[10px] font-bold tracking-widest transition-all ${tempLang === lang ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>
                  {lang.toUpperCase()}
                </button>
              ))}
            </div>
          </header>
          <div className="max-w-4xl w-full text-center space-y-12 animate-in fade-in duration-1000 mt-20 pb-20">
            <h1 className="text-6xl md:text-8xl font-extrabold tracking-tighter leading-tight bg-gradient-to-b from-white to-slate-500 bg-clip-text text-transparent">
              Think beyond <br/><span className="text-indigo-500">Limits.</span>
            </h1>
            <p className="text-xl text-slate-400 max-w-2xl mx-auto font-medium">{t.heroSub}</p>
            <div className="flex flex-col md:flex-row gap-6 justify-center pt-8">
              <button onClick={() => setAuthMode('register')} className="bg-indigo-600 px-12 py-4 rounded-2xl font-bold uppercase tracking-widest hover:brightness-110 transition-all shadow-[0_0_30px_rgba(79,70,229,0.3)]">{t.register}</button>
              <button onClick={() => setAuthMode('login')} className="bg-transparent border border-white/10 px-12 py-4 rounded-2xl font-bold uppercase tracking-widest hover:bg-white/5 transition-all text-slate-300">{t.login}</button>
            </div>
          </div>
        </div>
      );
    }
    return (
      <div className="h-screen w-full bg-[#020204] flex items-center justify-center p-4 text-slate-100 overflow-y-auto custom-scrollbar">
        <form onSubmit={handleAuth} className="glass p-12 rounded-[2.5rem] max-w-lg w-full shadow-2xl space-y-8 border-indigo-500/10">
          <h2 className="text-3xl font-black text-center uppercase tracking-tight">{authMode === 'register' ? t.register : t.login}</h2>
          <div className="space-y-4">
            {authMode === 'register' && <input name="name" placeholder="Name" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none text-white" />}
            <input name="email" type="email" placeholder="Email" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none text-white" />
            <input name="password" type="password" placeholder="Password" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none text-white" />
            {authMode === 'register' && (
              <div className="flex gap-4">
                <select name="class" className="flex-1 bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm text-slate-400">
                  {CLASSES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <select name="language" className="flex-1 bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm text-slate-400">
                  <option value="ru">RU</option>
                  <option value="en">EN</option>
                  <option value="uz">UZ</option>
                </select>
              </div>
            )}
          </div>
          <button type="submit" className="w-full bg-indigo-600 py-4 rounded-2xl font-bold uppercase tracking-widest shadow-xl">{authMode === 'register' ? 'Join' : 'Enter'}</button>
          <button type="button" onClick={() => setAuthMode(authMode === 'register' ? 'login' : 'register')} className="w-full text-slate-500 text-[10px] font-bold uppercase tracking-widest hover:text-indigo-400">
            {authMode === 'register' ? 'Login instead' : 'Register instead'}
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="h-screen w-full flex bg-[#020204] text-slate-100 overflow-hidden font-sans">
      {/* Sidebar - Fixed height and scrollable if needed */}
      <nav className="w-72 bg-[#0a0a0b] hidden lg:flex flex-col py-8 border-r border-white/5 h-full">
        <div className="px-8 mb-12 flex items-center gap-3">
          <div className="w-9 h-9 bg-gradient-to-tr from-blue-600 to-indigo-500 rounded-xl flex items-center justify-center font-bold text-xl text-white shadow-lg">C</div>
          <span className="font-bold text-xl tracking-tight">Switcher</span>
        </div>

        <div className="flex-1 flex flex-col gap-1.5 px-5 overflow-y-auto custom-scrollbar">
          <SideItem icon="grid" label={t.dashboard} active={view === 'dashboard'} onClick={() => setView('dashboard')} />
          <SideItem icon="lightbulb" label={t.conceptTeacher} active={view === 'teacher'} onClick={() => { setView('teacher'); setMessages([]); }} />
          <SideItem icon="brain" label={t.thinkingCoach} active={view === 'coach'} onClick={() => { setView('coach'); setMessages([]); }} />
          <SideItem icon="tasks" label={t.adaptiveTasks} active={view === 'tasks'} onClick={() => setView('tasks')} />
          <SideItem icon="trophy" label={t.wallOfFame} active={view === 'leaderboard'} onClick={() => setView('leaderboard')} />
          <SideItem icon="user" label={t.myProfile} active={view === 'profile'} onClick={() => setView('profile')} />
          {user.isAdmin && <SideItem icon="shield" label={t.admin} active={view === 'admin'} onClick={() => setView('admin')} />}
        </div>

        <div className="px-5 mt-auto pt-6">
          <div className="bg-[#121214] p-4 rounded-2xl flex items-center gap-3 border border-white/5 shadow-inner">
            <div className="w-10 h-10 bg-indigo-600/20 rounded-full flex items-center justify-center text-indigo-400 font-bold text-lg">{user.name[0]}</div>
            <div className="overflow-hidden">
              <p className="font-bold text-sm truncate">{user.name}</p>
              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">GRADE {user.studentClass}</p>
            </div>
            <div className="ml-auto w-2 h-2 bg-green-500 rounded-full shadow-[0_0_12px_rgba(34,197,94,0.6)] animate-pulse"></div>
          </div>
        </div>
      </nav>

      {/* Main Content Area - Properly contained for scrolling */}
      <main className="flex-1 h-full overflow-hidden flex flex-col relative">
        <div className="flex-1 overflow-y-auto custom-scrollbar">
          {view === 'dashboard' && (
            <div className="p-8 md:p-12 max-w-5xl mx-auto w-full space-y-16 pb-32 animate-in fade-in duration-700">
              <div className="space-y-2">
                <h2 className="text-4xl md:text-5xl font-black tracking-tighter bg-gradient-to-r from-white to-slate-500 bg-clip-text text-transparent uppercase">
                  Neural <span className="text-indigo-500">Center</span>
                </h2>
                <p className="text-slate-500 font-bold uppercase tracking-[0.5em] text-[10px]">Status: Registry Operational</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <DashboardCard label="Sync Level" value={`${user.level}`} icon="🌟" gradient="from-indigo-600 to-indigo-800" />
                <DashboardCard label="Cognitive XP" value={`${user.xp}`} icon="⚡" gradient="from-blue-600 to-blue-800" />
              </div>

              {/* Featured Quote Section */}
              <div className="bg-gradient-to-br from-[#1a1a1c] to-[#0a0a0b] border border-white/5 p-10 md:p-12 rounded-[2.5rem] shadow-2xl relative overflow-hidden group text-center">
                 <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-indigo-500/50 to-transparent"></div>
                 <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.6em] mb-6">{t.quotes}</p>
                 <p className="text-xl md:text-2xl font-bold tracking-tight text-white leading-snug italic mb-4 transition-all group-hover:scale-[1.01]">
                   "{QUOTES[Math.floor(Date.now() / 86400000) % QUOTES.length].text}"
                 </p>
                 <p className="text-xs text-slate-500 font-black tracking-widest uppercase">— {QUOTES[Math.floor(Date.now() / 86400000) % QUOTES.length].author}</p>
              </div>

              {/* Knowledge Nodes (Articles) */}
              <div className="space-y-10">
                 <div className="flex items-center gap-4">
                   <h3 className="text-lg md:text-xl font-black uppercase tracking-[0.3em] text-slate-300">{t.articles}</h3>
                   <div className="h-px flex-1 bg-white/5"></div>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    {ARTICLES.map(art => (
                      <div key={art.id} className={`bg-gradient-to-br ${art.gradient} p-8 rounded-[2.25rem] border border-white/5 hover:border-indigo-500/30 transition-all group relative overflow-hidden h-full flex flex-col`}>
                         <div className="text-5xl mb-6 group-hover:scale-110 transition-transform duration-500">{art.icon}</div>
                         <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">{art.category}</p>
                         <h4 className="text-xl md:text-2xl font-bold text-white mb-4 leading-tight">{art.title}</h4>
                         <p className="text-sm text-slate-300 leading-relaxed font-medium">{art.content}</p>
                         <div className={`mt-auto pt-6 w-full h-1 rounded-full ${art.accent} opacity-20 group-hover:opacity-60 transition-opacity`}></div>
                      </div>
                    ))}
                 </div>
              </div>

              {/* Feedback / Reviews Section */}
              <div className="space-y-12 bg-[#0a0a0b] p-8 md:p-12 rounded-[3rem] border border-white/5 shadow-2xl">
                 <div className="flex flex-col md:flex-row justify-between items-center gap-6">
                   <h3 className="text-lg md:text-xl font-black uppercase tracking-[0.3em] text-slate-300">{t.reviews}</h3>
                   <div className="flex items-center gap-2 bg-[#121214] border border-white/5 rounded-2xl p-1.5 shadow-inner">
                      {[1, 2, 3, 4, 5].map(star => (
                        <button 
                          key={star} 
                          onClick={() => setReviewRating(star)} 
                          className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all ${reviewRating >= star ? 'bg-yellow-500 text-white shadow-lg shadow-yellow-500/20' : 'text-slate-700 hover:text-slate-500'}`}
                        >
                          ★
                        </button>
                      ))}
                   </div>
                 </div>

                 <div className="space-y-8">
                    <div className="flex flex-col md:flex-row gap-4">
                      <textarea 
                        value={reviewInput}
                        onChange={e => setReviewInput(e.target.value)}
                        placeholder={t.writeReview}
                        className="flex-1 bg-[#121214] border border-white/10 rounded-2xl p-5 text-sm focus:border-indigo-500 outline-none transition-all placeholder:text-slate-600 resize-none h-20"
                      />
                      <button 
                        onClick={submitReview}
                        className="bg-indigo-600 px-8 rounded-2xl font-black text-xs uppercase tracking-widest hover:brightness-110 active:scale-95 transition-all shadow-xl h-20"
                      >
                        {t.submit}
                      </button>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4">
                       {reviews.length === 0 ? (
                         <div className="col-span-2 py-10 text-center text-slate-600 text-sm font-bold uppercase tracking-widest">{t.noReviews}</div>
                       ) : (
                         reviews.map((rev, i) => (
                          <div key={i} className="bg-[#121214]/60 border border-white/5 p-8 rounded-[1.75rem] space-y-4 animate-in slide-in-from-bottom-4">
                             <div className="flex justify-between items-start">
                               <div className="flex items-center gap-3">
                                 <div className="w-8 h-8 bg-indigo-500/10 rounded-lg flex items-center justify-center text-xs font-bold text-indigo-400">{rev.name[0]}</div>
                                 <p className="font-black text-[11px] uppercase tracking-widest text-white">{rev.name}</p>
                               </div>
                               <div className="text-[10px] text-yellow-500 font-bold">{'★'.repeat(rev.rating)}</div>
                             </div>
                             <p className="text-sm text-slate-400 italic leading-relaxed font-medium">"{rev.text}"</p>
                          </div>
                         ))
                       )}
                    </div>
                 </div>
              </div>
            </div>
          )}

          {(view === 'teacher' || view === 'coach') && (
            <div className="p-8 md:p-12 max-w-5xl mx-auto w-full animate-in fade-in slide-in-from-bottom-4 duration-500 pb-32">
              <div className="mb-10 space-y-1">
                <div className="flex items-center gap-4">
                  <span className="text-4xl">{view === 'teacher' ? '🧬' : '🧠'}</span>
                  <h2 className="text-3xl md:text-4xl font-extrabold tracking-tight text-white">{view === 'teacher' ? t.conceptTeacher : t.thinkingCoach}</h2>
                </div>
                <p className="text-slate-500 font-semibold ml-14 text-lg">{view === 'teacher' ? t.teacherDesc : t.coachDesc}</p>
              </div>

              <div className="space-y-8">
                {messages.length === 0 ? (
                  <div className="py-20 flex flex-col items-center justify-center text-center opacity-30 space-y-6">
                    <div className="w-24 h-24 bg-white/5 rounded-[2.5rem] flex items-center justify-center text-6xl">{view === 'teacher' ? '📖' : '💭'}</div>
                    <p className="text-2xl font-bold tracking-tight">{t.pasteProblem}</p>
                  </div>
                ) : (
                  messages.map((m, i) => (
                    <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
                      <div className={`max-w-[75%] p-6 rounded-[1.5rem] text-[16px] leading-relaxed shadow-xl border ${m.role === 'user' ? 'bg-[#1a1a1c] border-white/10 text-white' : 'bg-[#1a1a1c]/60 border-indigo-500/20 text-slate-200'}`}>
                        {m.text}
                      </div>
                    </div>
                  ))
                )}
                {isLoading && (
                  <div className="flex items-center gap-3 ml-2">
                    <div className="flex gap-1.5"><div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div><div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div><div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce"></div></div>
                    <span className="text-[10px] text-indigo-400 font-black uppercase tracking-[0.4em]">Processing Node</span>
                  </div>
                )}
              </div>
            </div>
          )}

          {view === 'tasks' && (
            <div className="p-8 md:p-12 max-w-2xl mx-auto w-full text-center space-y-12 pb-32">
              <h2 className="text-3xl md:text-4xl font-black tracking-tight uppercase">Mission Control</h2>
              <div className="bg-gradient-to-br from-indigo-600 to-blue-700 p-12 md:p-16 rounded-[3rem] border border-white/10 space-y-8 shadow-2xl">
                 <div className="text-7xl">🎯</div>
                 <p className="text-white/80 font-bold text-lg">Initiate a personalized mission to expand your cognitive boundaries.</p>
                 <button onClick={getNewTask} className="w-full bg-white text-indigo-900 py-5 rounded-2xl font-black uppercase tracking-[0.2em] shadow-xl hover:scale-[1.02] transition-all">Initialize Task</button>
              </div>
              {currentTask && (
                <div className="text-left p-10 bg-[#0a0a0b] border-indigo-500/30 border rounded-[2rem] space-y-6 animate-in zoom-in">
                  <div className="flex justify-between items-center"><span className="text-[10px] font-black uppercase text-indigo-400 px-3 py-1 bg-indigo-500/10 rounded-full">{currentTask.difficulty}</span><span className="font-bold text-indigo-400">+{currentTask.xpReward} XP</span></div>
                  <h4 className="text-2xl font-bold uppercase text-white">{currentTask.title}</h4>
                  <p className="text-sm text-slate-300 leading-relaxed font-medium">{currentTask.description}</p>
                </div>
              )}
