import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, Message } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const getSystemInstruction = (role: 'teacher' | 'coach' | 'trainer', profile: UserProfile) => {
  const interests = profile.interests.join(', ');
  const lang = profile.language === 'ru' ? 'Russian' : profile.language === 'uz' ? 'Uzbek' : 'English';

  const base = `Respond in ${lang}. The student is in class ${profile.studentClass} and loves ${interests}. `;

  if (role === 'teacher') {
    return base + `You are a Concept Teacher. Explain complex topics ONLY through metaphors related to the student's interests (${interests}). Simplify, but don't give the final answer if it's a problem-solving request. If the user provides an image or file, analyze it and incorporate it into your explanation.`;
  }
  if (role === 'coach') {
    return base + `You are a Socratic Coach. Never give direct answers. Ask 1-2 powerful questions that guide the student's thinking. If they are wrong, encourage them to rethink the logic. Use any uploaded images to help contextualize your questions.`;
  }
  return base + `You are an Adaptive Trainer. Generate a small learning task or question based on the user's input or provided files. Do not provide the solution. Evaluate their response based on reasoning.`;
};

export async function askAI(role: 'teacher' | 'coach' | 'trainer', prompt: string, profile: UserProfile, history: Message[] = []) {
  const instruction = getSystemInstruction(role, profile);

  // Format history and current parts
  const formattedContents = history.map(m => {
    const parts: any[] = [{ text: m.text }];
    if (m.attachment) {
      parts.push({
        inlineData: {
          mimeType: m.attachment.mimeType,
          data: m.attachment.data
        }
      });
    }
    return { role: m.role, parts };
  });

  // Current prompt part
  const lastMessage = formattedContents[formattedContents.length - 1];

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest', // Fast and multimodal
    contents: formattedContents,
    config: {
      systemInstruction: instruction,
    }
  });

  return response.text;
}

export async function generateAdaptiveTask(profile: UserProfile) {
  const lang = profile.language === 'ru' ? 'Russian' : profile.language === 'uz' ? 'Uzbek' : 'English';

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a unique learning task for a student in class ${profile.studentClass} who likes ${profile.interests.join(', ')}. Respond in JSON. Language: ${lang}.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          difficulty: { type: Type.STRING, enum: ['easy', 'medium', 'challenge'] },
          description: { type: Type.STRING },
          xpReward: { type: Type.NUMBER }
        },
        required: ["title", "difficulty", "description", "xpReward"]
      }
    }
  });

  const jsonStr = response.text || '{}';
  return JSON.parse(jsonStr.trim());
}

