            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gradient-to-tr from-blue-600 to-indigo-500 rounded-xl flex items-center justify-center font-black text-white shadow-lg">TF</div>
              <span className="font-bold text-2xl tracking-tighter">ThinkFlow</span>
            </div>
            <div className="flex bg-[#0f172a] rounded-lg p-1 border border-white/5">
              {(['ru', 'en', 'uz'] as const).map((lang) => (
                <button key={lang} onClick={() => setTempLang(lang)} className={`px-4 py-1 rounded-md text-[10px] font-bold tracking-widest transition-all ${tempLang === lang ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>
                  {lang.toUpperCase()}
                </button>
              ))}
            </div>
          </header>
          <div className="max-w-4xl w-full text-center space-y-12 animate-in fade-in duration-1000 mt-20 pb-20">
            <h1 className="text-6xl md:text-8xl font-extrabold tracking-tighter leading-tight bg-gradient-to-b from-white to-slate-500 bg-clip-text text-transparent">Think beyond <br/><span className="text-indigo-500">Limits.</span></h1>
            <p className="text-xl text-slate-400 max-w-2xl mx-auto font-medium">{t.heroSub}</p>
            <div className="flex flex-col md:flex-row gap-6 justify-center pt-8">
              <button onClick={() => { setAuthMode('register'); setAuthError(null); }} className="bg-indigo-600 px-12 py-4 rounded-2xl font-bold uppercase tracking-widest hover:brightness-110 transition-all shadow-xl">{t.register}</button>
              <button onClick={() => { setAuthMode('login'); setAuthError(null); }} className="bg-transparent border border-white/10 px-12 py-4 rounded-2xl font-bold uppercase tracking-widest hover:bg-white/5 transition-all text-slate-300">{t.login}</button>
            </div>
          </div>
        </div>
      );
    }
    return (
      <div className="h-screen w-full bg-[#020204] flex items-center justify-center p-4 text-slate-100 overflow-y-auto custom-scrollbar">
        <form onSubmit={handleAuth} className="glass p-12 rounded-[2.5rem] max-w-lg w-full shadow-2xl space-y-8 border-indigo-500/10 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-indigo-500 to-transparent"></div>
          <h2 className="text-3xl font-black text-center uppercase tracking-tight">{authMode === 'register' ? t.register : t.login}</h2>

          {authError && (
            <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-500 text-xs font-bold text-center animate-bounce">
              {authError}
            </div>
          )}

          <div className="space-y-4">
            {authMode === 'register' && <input name="name" placeholder="Name" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none text-white transition-all" />}
            <input name="email" type="email" placeholder="Email" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none text-white transition-all" />
