                  <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 px-2">Initialize Interests</p>
                  <div className="grid grid-cols-3 gap-2">
                    {INTERESTS_POOL.slice(0, 9).map(i => (
                      <label key={i} className="flex items-center gap-2 p-2 bg-[#0a0a0b] border border-white/5 rounded-xl cursor-pointer hover:bg-white/5 transition-all">
