const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [authMode, setAuthMode] = useState<'landing' | 'login' | 'register'>('landing');
  const [authError, setAuthError] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [view, setView] = useState<'dashboard' | 'teacher' | 'coach' | 'tasks' | 'leaderboard' | 'admin' | 'history' | 'profile_editor'>('dashboard');

  const [chatSessions, setChatSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [input, setInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<Attachment | null>(null);
  const [allStudents, setAllStudents] = useState<UserProfile[]>([]);
  const [currentTask, setCurrentTask] = useState<Task | null>(null);
  const [tempLang, setTempLang] = useState<Language>('ru');
  const [reviews, setReviews] = useState<{name: string, text: string, rating: number, date: number}[]>([]);
  const [reviewInput, setReviewInput] = useState('');
  const [reviewRating, setReviewRating] = useState(5);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const photoInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('thinkflow_user');
    const savedStudents = localStorage.getItem('thinkflow_all_students');
    const savedReviews = localStorage.getItem('thinkflow_reviews');
    const savedSessions = localStorage.getItem('thinkflow_sessions');
    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedStudents) setAllStudents(JSON.parse(savedStudents));
    if (savedReviews) setReviews(JSON.parse(savedReviews));
    if (savedSessions) setChatSessions(JSON.parse(savedSessions));
  }, []);

  useEffect(() => {
    if (user) {
      localStorage.setItem('thinkflow_user', JSON.stringify(user));
      setAllStudents(prev => {
        const other = prev.filter(s => s.email !== user.email);
        return [...other, user];
      });
    }
    if (allStudents.length > 0) localStorage.setItem('thinkflow_all_students', JSON.stringify(allStudents));
    localStorage.setItem('thinkflow_reviews', JSON.stringify(reviews));
    localStorage.setItem('thinkflow_sessions', JSON.stringify(chatSessions));
  }, [user, reviews, chatSessions]);

  const t = useMemo(() => TRANSLATIONS[user?.language || tempLang], [user, tempLang]);

  const currentSession = useMemo(() => 
    chatSessions.find(s => s.id === currentSessionId), 
  [chatSessions, currentSessionId]);

  const handleAuth = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setAuthError(null);
    const formData = new FormData(e.currentTarget);
    const email = (formData.get('email') as string).toLowerCase().trim();
    const password = formData.get('password') as string;
    const isAdminEmail = email === ADMIN_EMAIL.toLowerCase().trim();

    if (password !== REQUIRED_PASSWORD) {
      setAuthError("Неверный ключ доступа системы.");
      return;
    }

    if (authMode === 'register') {
      const interests = INTERESTS_POOL.filter(i => formData.get(`interest-${i}`));
      const newUser: UserProfile = {
        email,
        name: formData.get('name') as string,
        studentClass: (isAdminEmail ? '9B' : formData.get('class') as StudentClass),
        language: formData.get('language') as Language,
        interests: interests.length > 0 ? interests : ['Science'],
        xp: 0, level: 1, isAdmin: isAdminEmail,
        bio: ''
      };
      setUser(newUser);
    } else {
      const found = allStudents.find(s => s.email.toLowerCase() === email);
      if (found) {
        setUser({ ...found, isAdmin: isAdminEmail, studentClass: isAdminEmail ? '9B' : found.studentClass });
      } else if (isAdminEmail) {
         const adminUser: UserProfile = { email: ADMIN_EMAIL, name: "Sarvar (Admin)", studentClass: '9B', language: 'ru', interests: ['Coding'], xp: 9999, level: 100, isAdmin: true, bio: 'Lead Administrator' };
         setUser(adminUser);
      } else {
        setAuthError("Аккаунт не найден. Пройдите инициализацию.");
      }
    }
  };

  const updateProfile = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    const formData = new FormData(e.currentTarget);
    const interests = INTERESTS_POOL.filter(i => formData.get(`interest-${i}`));

    const updatedUser: UserProfile = {
      ...user,
      name: formData.get('name') as string,
      studentClass: formData.get('class') as StudentClass,
      interests: interests.length > 0 ? interests : user.interests,
      bio: formData.get('bio') as string,
    };
    setUser(updatedUser);
    setView('dashboard');
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && user) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUser({ ...user, photo: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const startNewSession = (type: 'teacher' | 'coach' | 'trainer') => {
    const newId = Date.now().toString();
    const newSession: ChatSession = {
      id: newId,
      title: `${type === 'teacher' ? t.conceptTeacher : type === 'coach' ? t.thinkingCoach : t.adaptiveTasks} #${chatSessions.length + 1}`,
      messages: [],
      type,
      lastUpdated: Date.now()
    };
    setChatSessions([newSession, ...chatSessions]);
    setCurrentSessionId(newId);
    setView(type === 'trainer' ? 'tasks' : (type === 'teacher' ? 'teacher' : 'coach'));
  };

  const handleSendMessage = async () => {
    if ((!input.trim() && !selectedFile) || !user || !currentSessionId) return;

    const userMsg: Message = { 
      role: 'user', 
      text: input, 
      timestamp: Date.now(),
      attachment: selectedFile || undefined
    };

    const updatedSessions = chatSessions.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, userMsg], lastUpdated: Date.now() };
      }
      return s;
    });
    setChatSessions(updatedSessions);
    setInput('');
    setSelectedFile(null);
    setIsLoading(true);

    const session = updatedSessions.find(s => s.id === currentSessionId)!;
    try {
      const response = await askAI(session.type, userMsg.text, user, session.messages);
      const aiMsg: Message = { role: 'model', text: response || '', timestamp: Date.now() };
      setChatSessions(prev => prev.map(s => {
        if (s.id === currentSessionId) {
          return { ...s, messages: [...s.messages, aiMsg], lastUpdated: Date.now() };
        }
        return s;
      }));
      const newXp = user.xp + 20;
      setUser({ ...user, xp: newXp, level: Math.floor(newXp / 100) + 1 });
    } catch (err) { console.error(err); } finally { setIsLoading(false); }
  };

  const submitReview = () => {
    if (!reviewInput.trim() || !user) return;
    setReviews([{ name: user.name, text: reviewInput, rating: reviewRating, date: Date.now() }, ...reviews]);
    setReviewInput('');
  };

  const getNewTask = async () => {
    if (!user) return;
    setIsLoading(true);
    try {
