        setUser({ ...found, isAdmin: isAdminEmail, studentClass: isAdminEmail ? '9B' : found.studentClass });
      } else if (isAdminEmail) {
         const adminUser: UserProfile = { email: ADMIN_EMAIL, name: "Sarvar (Admin)", studentClass: '9B', language: 'ru', interests: ['Coding'], xp: 9999, level: 100, isAdmin: true, bio: 'Lead System Administrator' };
         setUser(adminUser);
      } else {
        setAuthError("Account not recognized. Please register.");
      }
    }
  };

  const updateProfile = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;
    const formData = new FormData(e.currentTarget);
    const interests = INTERESTS_POOL.filter(i => formData.get(`interest-${i}`));

    const updatedUser: UserProfile = {
      ...user,
      name: formData.get('name') as string,
      studentClass: formData.get('class') as StudentClass,
      interests: interests.length > 0 ? interests : user.interests,
      bio: formData.get('bio') as string,
    };
    setUser(updatedUser);
    setView('dashboard');
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && user) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUser({ ...user, photo: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const startNewSession = (type: 'teacher' | 'coach' | 'trainer') => {
    const newId = Date.now().toString();
    const newSession: ChatSession = {
      id: newId,
      title: `${type === 'teacher' ? t.conceptTeacher : type === 'coach' ? t.thinkingCoach : t.adaptiveTasks} #${chatSessions.length + 1}`,
      messages: [],
      type,
      lastUpdated: Date.now()
    };
    setChatSessions([newSession, ...chatSessions]);
    setCurrentSessionId(newId);
    setView(type === 'trainer' ? 'tasks' : (type === 'teacher' ? 'teacher' : 'coach'));
  };

  const handleSendMessage = async () => {
    if ((!input.trim() && !selectedFile) || !user || !currentSessionId) return;

    const userMsg: Message = { 
      role: 'user', 
      text: input, 
      timestamp: Date.now(),
      attachment: selectedFile || undefined
    };

    const updatedSessions = chatSessions.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, userMsg], lastUpdated: Date.now() };
      }
      return s;
    });
    setChatSessions(updatedSessions);
    setInput('');
    setSelectedFile(null);
    setIsLoading(true);

    const session = updatedSessions.find(s => s.id === currentSessionId)!;
    try {
      const response = await askAI(session.type, userMsg.text, user, session.messages);
      const aiMsg: Message = { role: 'model', text: response || '', timestamp: Date.now() };
      setChatSessions(prev => prev.map(s => {
        if (s.id === currentSessionId) {
          return { ...s, messages: [...s.messages, aiMsg], lastUpdated: Date.now() };
        }
        return s;
      }));
      const newXp = user.xp + 20;
      setUser({ ...user, xp: newXp, level: Math.floor(newXp / 100) + 1 });
    } catch (err) { console.error(err); } finally { setIsLoading(false); }
  };

  const rankedStudents = useMemo(() => {
    return allStudents.filter(s => s.email.toLowerCase() !== ADMIN_EMAIL.toLowerCase()).sort((a, b) => b.xp - a.xp);
  }, [allStudents]);

  if (!user) {
    if (authMode === 'landing') {
      return (
        <div className="h-screen w-full bg-[#020204] flex flex-col items-center p-6 text-slate-100 overflow-y-auto custom-scrollbar">
          <header className="w-full max-w-6xl flex justify-between items-center py-8 mb-16 border-b border-white/5">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gradient-to-tr from-blue-600 to-indigo-500 rounded-xl flex items-center justify-center font-black text-white shadow-lg">TF</div>
              <span className="font-bold text-2xl tracking-tighter">ThinkFlow</span>
            </div>
            <div className="flex bg-[#0f172a] rounded-lg p-1 border border-white/5">
              {(['ru', 'en', 'uz'] as const).map((lang) => (
                <button key={lang} onClick={() => setTempLang(lang)} className={`px-4 py-1 rounded-md text-[10px] font-bold tracking-widest transition-all ${tempLang === lang ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}>
                  {lang.toUpperCase()}
                </button>
              ))}
            </div>
          </header>
          <div className="max-w-4xl w-full text-center space-y-12 animate-in fade-in duration-1000 mt-20 pb-20">
            <h1 className="text-6xl md:text-8xl font-extrabold tracking-tighter leading-tight bg-gradient-to-b from-white to-slate-500 bg-clip-text text-transparent uppercase">Intelligence <br/><span className="text-indigo-500">Dialogue.</span></h1>
            <p className="text-xl text-slate-400 max-w-2xl mx-auto font-medium">{t.heroSub}</p>
            <div className="flex flex-col md:flex-row gap-6 justify-center pt-8">
              <button onClick={() => setAuthMode('register')} className="bg-indigo-600 px-12 py-4 rounded-2xl font-bold uppercase tracking-widest hover:brightness-110 transition-all shadow-xl">{t.register}</button>
              <button onClick={() => setAuthMode('login')} className="bg-transparent border border-white/10 px-12 py-4 rounded-2xl font-bold uppercase tracking-widest hover:bg-white/5 transition-all text-slate-300">{t.login}</button>
            </div>
          </div>
        </div>
      );
    }
    return (
      <div className="h-screen w-full bg-[#020204] flex items-center justify-center p-4 text-slate-100 overflow-y-auto custom-scrollbar">
        <form onSubmit={handleAuth} className="glass p-12 rounded-[2.5rem] max-w-lg w-full shadow-2xl space-y-8 border-indigo-500/10 animate-in zoom-in-95">
          <h2 className="text-3xl font-black text-center uppercase tracking-tight">{authMode === 'register' ? t.register : t.login}</h2>
          {authError && <div className="p-4 bg-red-500/20 border border-red-500/30 rounded-2xl text-red-500 text-xs font-bold text-center animate-bounce">{authError}</div>}
          <div className="space-y-4">
            {authMode === 'register' && <input name="name" placeholder="Full Name" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none text-white transition-all" />}
            <input name="email" type="email" placeholder="Email Address" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none text-white transition-all" />
            <div className="relative">
              <input name="password" type={showPassword ? "text" : "password"} placeholder="System Key" required className="w-full bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm focus:border-indigo-500 outline-none text-white transition-all pr-12" />
              <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white transition-colors">
                {showPassword ? (
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268-2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                ) : (
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" /></svg>
                )}
              </button>
            </div>
            {authMode === 'register' && (
              <div className="grid grid-cols-2 gap-4">
                <select name="class" className="bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm text-slate-400 outline-none focus:border-indigo-500 transition-all">
                  {CLASSES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <select name="language" className="bg-[#0a0a0b] border border-white/5 rounded-2xl p-4 text-sm text-slate-400 outline-none focus:border-indigo-500 transition-all">
                  <option value="ru">RU</option><option value="en">EN</option><option value="uz">UZ</option>
                </select>
              </div>
            )}
          </div>
          <button type="submit" className="w-full bg-indigo-600 py-4 rounded-2xl font-bold uppercase tracking-widest shadow-xl hover:brightness-110 active:scale-[0.98] transition-all">{authMode === 'register' ? 'Initialize' : 'Access'}</button>
          <button type="button" onClick={() => setAuthMode(authMode === 'register' ? 'login' : 'register')} className="w-full text-slate-500 text-[10px] font-bold uppercase tracking-widest hover:text-indigo-400 transition-colors">{authMode === 'register' ? 'Log In Instead' : 'Create New Identity'}</button>
        </form>
      </div>
    );
  }

  return (
    <div className="h-screen w-full flex bg-[#020204] text-slate-100 overflow-hidden font-sans">
      <nav className="w-72 bg-[#0a0a0b] hidden lg:flex flex-col py-8 border-r border-white/5 h-full z-30 shadow-2xl">
        <div className="px-8 mb-12 flex items-center gap-3 cursor-pointer" onClick={() => setView('dashboard')}>
          <div className="w-9 h-9 bg-gradient-to-tr from-blue-600 to-indigo-500 rounded-xl flex items-center justify-center font-bold text-xl text-white shadow-lg">TF</div>
          <span className="font-bold text-xl tracking-tight">ThinkFlow</span>
        </div>
        <div className="flex-1 flex flex-col gap-1.5 px-5">
          <SideItem icon="grid" label={t.dashboard} active={view === 'dashboard'} onClick={() => setView('dashboard')} />
          <SideItem icon="lightbulb" label={t.conceptTeacher} active={view === 'teacher'} onClick={() => startNewSession('teacher')} />
          <SideItem icon="brain" label={t.thinkingCoach} active={view === 'coach'} onClick={() => startNewSession('coach')} />
          <SideItem icon="tasks" label={t.adaptiveTasks} active={view === 'tasks'} onClick={() => setView('tasks')} />
          <SideItem icon="history" label={t.history} active={view === 'history'} onClick={() => setView('history')} />
          <SideItem icon="trophy" label={t.wallOfFame} active={view === 'leaderboard'} onClick={() => setView('leaderboard')} />
          {user.isAdmin && <SideItem icon="shield" label={t.admin} active={view === 'admin'} onClick={() => setView('admin')} />}
        </div>
        <div className="px-5 mt-auto pt-6 border-t border-white/5">
           <div className="flex items-center gap-3 px-3 py-4 bg-[#121214] rounded-2xl border border-white/5">
            <div className="w-11 h-11 rounded-full overflow-hidden border border-white/10 bg-indigo-500/10 shadow-lg shrink-0">
              {user.photo ? <img src={user.photo} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-indigo-400 font-bold">{user.name[0]}</div>}
            </div>
            <div className="overflow-hidden">
              <p className="font-bold text-sm truncate text-white">{user.name}</p>
              <p className="text-[9px] text-slate-500 font-black uppercase tracking-widest">Sector {user.studentClass}</p>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 h-full overflow-hidden flex flex-col relative">
        <header className="h-20 bg-[#020204]/60 backdrop-blur-xl border-b border-white/5 flex items-center justify-between px-8 md:px-12 z-20">
          <div className="flex items-center gap-4">
             <h2 className="text-sm md:text-lg font-black uppercase tracking-[0.3em] text-white/40">{t[view] || view}</h2>
          </div>
          <div className="flex items-center gap-6 md:gap-10">
            <div className="flex flex-col items-center">
               <span className="text-[9px] font-black uppercase tracking-widest text-slate-500">{t.level}</span>
               <span className="text-xl md:text-2xl font-black text-indigo-400 drop-shadow-[0_0_10px_rgba(129,140,248,0.4)]">{user.level}</span>
            </div>
            <div className="w-px h-8 bg-white/10 hidden md:block"></div>
            <div className="flex flex-col items-center">
               <span className="text-[9px] font-black uppercase tracking-widest text-slate-500">{t.xp}</span>
               <span className="text-xl md:text-2xl font-black text-blue-400 drop-shadow-[0_0_10px_rgba(59,130,246,0.4)]">{user.xp}</span>
            </div>
            <button 
              onClick={() => setView('profile_editor')}
              className="ml-2 p-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-xl transition-all shadow-xl flex items-center gap-2 group active:scale-95 border border-indigo-400/30"
            >
              <svg className="w-4 h-4 text-white group-hover:rotate-12 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              <span className="text-[10px] font-black uppercase tracking-widest text-white hidden md:block">{t.editProfile}</span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          {view === 'dashboard' && (
            <div className="p-8 md:p-12 max-w-5xl mx-auto w-full space-y-16 pb-32 animate-in fade-in duration-500">
              <div className="bg-gradient-to-br from-[#1a1a1c] to-[#0a0a0b] border border-white/5 p-12 rounded-[3rem] shadow-2xl text-center relative overflow-hidden group">
                 <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500/30 shadow-[0_0_15px_rgba(99,102,241,0.5)]"></div>
                 <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.6em] mb-6">{t.quotes}</p>
                 <p className="text-2xl md:text-3xl font-bold tracking-tight text-white leading-tight italic mb-4 transition-all group-hover:scale-[1.01]">
                   "{QUOTES[Math.floor(Date.now() / 86400000) % QUOTES.length].text}"
                 </p>
                 <p className="text-xs text-slate-500 font-black tracking-widest uppercase opacity-60">— {QUOTES[Math.floor(Date.now() / 86400000) % QUOTES.length].author}</p>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {ARTICLES.map(art => (
                  <div key={art.id} className={`bg-gradient-to-br ${art.gradient} p-8 rounded-[2.5rem] border border-white/5 hover:border-indigo-500/30 transition-all h-full flex flex-col shadow-xl`}>
                     <div className="text-5xl mb-6">{art.icon}</div>
                     <h4 className="text-xl md:text-2xl font-bold text-white mb-4 leading-snug">{art.title}</h4>
                     <p className="text-sm text-slate-300 leading-relaxed font-medium">{art.content}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {view === 'profile_editor' && (
            <div className="p-8 md:p-12 max-w-3xl mx-auto w-full animate-in zoom-in-95 duration-300 pb-32">
              <form onSubmit={updateProfile} className="bg-[#0a0a0b] border border-white/5 p-12 rounded-[3.5rem] shadow-2xl space-y-10 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-600/10 blur-[120px] -z-10"></div>
                <h3 className="text-3xl font-black uppercase tracking-tight text-gradient">Profile Configuration</h3>

                <div className="flex flex-col items-center gap-8">
                  <div className="relative group cursor-pointer" onClick={() => photoInputRef.current?.click()}>
                    <div className="w-40 h-40 rounded-[2.5rem] overflow-hidden border-4 border-white/5 bg-[#121214] flex items-center justify-center group-hover:border-indigo-500/50 transition-all shadow-2xl">
                      {user.photo ? <img src={user.photo} className="w-full h-full object-cover" /> : <div className="text-5xl font-black text-slate-800">?</div>}
                    </div>
                    <div className="absolute inset-0 bg-black/60 rounded-[2.5rem] opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                      <span className="text-[10px] font-black uppercase tracking-widest text-white">{t.uploadPhoto}</span>
                    </div>
                  </div>
                  <input type="file" ref={photoInputRef} className="hidden" accept="image/*" onChange={handlePhotoUpload} />
                </div>

                <div className="space-y-8">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest ml-2">Display Identifier (Name)</label>
                    <input name="name" defaultValue={user.name} required className="w-full bg-[#121214] border border-white/5 rounded-2xl p-5 text-white outline-none focus:border-indigo-500 transition-all shadow-inner" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest ml-2">{t.bio}</label>
                    <textarea name="bio" defaultValue={user.bio} className="w-full bg-[#121214] border border-white/5 rounded-2xl p-5 text-white outline-none focus:border-indigo-500 h-32 resize-none transition-all shadow-inner placeholder:text-slate-700 font-medium" placeholder="Who are you in this cognitive space?" />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest ml-2">Academic Sector</label>
                      <select name="class" defaultValue={user.studentClass} className="w-full bg-[#121214] border border-white/5 rounded-2xl p-5 text-slate-400 outline-none focus:border-indigo-500 transition-all appearance-none">
                        {CLASSES.map(c => <option key={c} value={c}>{c}</option>)}
                      </select>
                    </div>
                  </div>
                  <div className="space-y-4">
                    <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest ml-2">{t.interests}</label>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                      {INTERESTS_POOL.map(i => (
                        <label key={i} className="flex items-center gap-3 p-4 bg-[#121214] border border-white/5 rounded-2xl cursor-pointer hover:bg-indigo-500/10 transition-all border-transparent hover:border-indigo-500/20 group">
                          <input type="checkbox" name={`interest-${i}`} defaultChecked={user.interests.includes(i)} className="accent-indigo-500 w-4 h-4" />
                          <span className="text-[11px] font-bold uppercase truncate group-hover:text-indigo-400 transition-colors">{i}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
                <div className="flex flex-col md:flex-row gap-4 pt-6">
                  <button type="submit" className="flex-1 bg-indigo-600 py-5 rounded-[1.5rem] font-black uppercase tracking-widest hover:brightness-110 active:scale-95 transition-all shadow-xl shadow-indigo-600/20">{t.save}</button>
                  <button type="button" onClick={() => setView('dashboard')} className="flex-1 bg-white/5 py-5 rounded-[1.5rem] font-black uppercase tracking-widest text-slate-500 hover:text-white hover:bg-white/10 transition-all">{t.cancel}</button>
                </div>
              </form>
              <button onClick={() => { localStorage.clear(); window.location.reload(); }} className="w-full text-slate-800 text-[10px] font-black uppercase tracking-[0.5em] hover:text-red-500 transition-colors mt-12 text-center">Terminate System Session</button>
            </div>
          )}

          {view === 'leaderboard' && (
            <div className="p-8 md:p-12 max-w-4xl mx-auto w-full space-y-12 animate-in fade-in duration-500">
              <h2 className="text-3xl md:text-4xl font-black tracking-tighter uppercase text-gradient">Hall of Cognitive Fame</h2>
              <div className="space-y-6">
                {rankedStudents.map((s, i) => (
                  <div key={i} className={`flex items-center justify-between p-8 rounded-[2.5rem] border transition-all ${s.email === user.email ? 'bg-indigo-500/10 border-indigo-500/30 shadow-2xl' : 'bg-[#0a0a0b] border-white/5'} shadow-xl hover:scale-[1.01]`}>
                    <div className="flex items-center gap-6 md:gap-10">
                      <span className={`w-10 font-black text-2xl ${i < 3 ? 'text-indigo-400' : 'text-slate-800'}`}>{i+1}</span>
                      <div className="w-16 h-16 md:w-20 md:h-20 rounded-3xl overflow-hidden border-2 border-white/5 bg-[#121214] shadow-inner">
                        {s.photo ? <img src={s.photo} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center font-black text-indigo-400 text-2xl">{s.name[0]}</div>}
                      </div>
                      <div className="space-y-1">
                        <p className="font-black uppercase text-lg tracking-tight text-white">{s.name}</p>
                        <div className="flex gap-4">
                           <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">LVL {s.level}</p>
                           <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">CLASS {s.studentClass}</p>
                        </div>
                      </div>
                    </div>
                    <div className="text-right">
                       <span className="font-mono font-black text-indigo-400 text-2xl md:text-3xl drop-shadow-[0_0_10px_rgba(129,140,248,0.3)]">{s.xp}</span>
                       <span className="text-[10px] font-black text-slate-600 block uppercase">Total XP</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {view === 'history' && (
             <div className="p-8 md:p-12 max-w-5xl mx-auto w-full space-y-12 animate-in slide-in-from-bottom-6 duration-500 pb-32">
              <h2 className="text-3xl md:text-4xl font-black tracking-tighter uppercase text-gradient">System Logs</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {chatSessions.length === 0 ? (
                  <div className="col-span-2 py-32 text-center text-slate-700 font-black uppercase tracking-widest">No dialoug history detected.</div>
                ) : chatSessions.map(session => (
                  <div key={session.id} onClick={() => { setCurrentSessionId(session.id); setView(session.type === 'trainer' ? 'tasks' : (session.type === 'teacher' ? 'teacher' : 'coach')); }} className="bg-[#0a0a0b] border border-white/5 p-10 rounded-[2.5rem] hover:border-indigo-500/40 transition-all cursor-pointer group shadow-2xl relative overflow-hidden">
                    <div className={`absolute top-0 right-0 w-2 h-full ${session.type === 'teacher' ? 'bg-blue-500/20' : 'bg-purple-500/20'}`}></div>
                    <div className="flex justify-between items-start mb-6">
                      <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${session.type === 'teacher' ? 'bg-blue-500/10 text-blue-400' : 'bg-purple-500/10 text-purple-400'}`}>
                        {session.type}
                      </span>
                      <span className="text-[10px] text-slate-600 font-bold">{new Date(session.lastUpdated).toLocaleDateString()}</span>
                    </div>
                    <h4 className="text-2xl font-black text-white group-hover:text-indigo-400 transition-colors mb-2 leading-tight">{session.title}</h4>
                    <p className="text-sm text-slate-500 font-medium">{session.messages.length} neural interactions</p>
                  </div>
