              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 md:gap-8">
                {chatSessions.length === 0 ? (
                  <div className="col-span-full py-32 text-center text-slate-700 font-black uppercase tracking-widest text-[10px]">Empty</div>
                ) : chatSessions.map(session => (
                  <div key={session.id} onClick={() => { setCurrentSessionId(session.id); setView(session.type === 'trainer' ? 'tasks' : (session.type === 'teacher' ? 'teacher' : 'coach')); }} className="bg-[#0a0a0b] border border-white/5 p-6 md:p-10 rounded-[1.5rem] md:rounded-[2.5rem] hover:border-indigo-500/40 transition-all cursor-pointer group shadow-2xl relative overflow-hidden">
                    <div className={`absolute top-0 right-0 w-1.5 h-full ${session.type === 'teacher' ? 'bg-blue-500/20' : 'bg-purple-500/20'}`}></div>
                    <div className="flex justify-between items-start mb-4 md:mb-6">
                      <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${session.type === 'teacher' ? 'bg-blue-500/10 text-blue-400' : 'bg-purple-500/10 text-purple-400'}`}>
                        {session.type}
