                  <div className="w-14 h-14 md:w-20 md:h-20 bg-indigo-500/10 rounded-2xl md:rounded-[2rem] flex items-center justify-center text-3xl md:text-5xl border border-white/5 shadow-inner">
                    {currentSession.type === 'teacher' ? '🧬' : '🧠'}
                  </div>
                  <div className="space-y-0.5 md:space-y-1">
                    <h2 className="text-xl md:text-4xl font-black tracking-tighter uppercase text-white truncate max-w-[150px] md:max-w-none">{currentSession.title}</h2>
                    <p className="text-slate-500 font-bold uppercase tracking-widest text-[8px] md:text-xs opacity-60">{currentSession.type === 'teacher' ? t.teacherDesc : t.coachDesc}</p>
                  </div>
                </div>
                <div className="space-y-6 md:space-y-10">
                  {currentSession.messages.length === 0 ? (
                    <div className="py-20 md:py-40 flex flex-col items-center justify-center text-center opacity-10">
                      <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center text-4xl md:text-6xl mb-6">✨</div>
                      <p className="text-xl md:text-3xl font-black uppercase tracking-widest">{t.pasteProblem}</p>
                    </div>
                  ) : currentSession.messages.map((m, i) => (
                    <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
                      <div className={`max-w-[90%] md:max-w-[80%] p-5 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border shadow-xl text-sm md:text-base leading-relaxed ${m.role === 'user' ? 'bg-[#1a1a1c] border-white/10 text-white' : 'bg-[#0a0a0b] border-indigo-500/20 text-slate-200'}`}>
                        {m.text}
                      </div>
                    </div>
                  ))}
                  {isLoading && (
                    <div className="flex items-center gap-3 ml-2">
                      <div className="flex gap-1.5"><div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></div><div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-100"></div><div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-200"></div></div>
                      <span className="text-[8px] text-indigo-400 font-black uppercase tracking-widest">Processing...</span>
                    </div>
                  )}
                </div>
            </div>
          )}
        </div>

        {/* Input Bar */}
        {(view === 'teacher' || view === 'coach') && currentSessionId && (
          <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 md:px-8 z-20">
            <div className="bg-[#121214]/80 backdrop-blur-3xl border border-white/10 rounded-[1.75rem] md:rounded-[2.5rem] p-2 flex items-center shadow-2xl animate-in slide-in-from-bottom-4">
              <input 
                value={input} 
                onChange={e => setInput(e.target.value)} 
                onKeyPress={e => e.key === 'Enter' && handleSendMessage()} 
                placeholder={t.startThinking} 
                className="flex-1 bg-transparent px-4 md:px-8 py-3 md:py-5 outline-none font-bold text-white text-sm md:text-lg placeholder:text-slate-700" 
              />
              <button onClick={handleSendMessage} className="w-12 h-12 md:w-16 md:h-16 bg-indigo-600 hover:bg-indigo-500 rounded-xl md:rounded-[1.75rem] flex items-center justify-center transition-all text-white shadow-xl active:scale-90 shrink-0">
                <svg className="w-6 h-6 md:w-8 md:h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
              </button>
            </div>
          </div>
        )}
      </main>

      {/* Mobile Sidebar Overlay Backdrop */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40 lg:hidden" onClick={() => setIsMobileMenuOpen(false)} />
      )}
    </div>
  );
};

const SideItem = ({ icon, label, active, onClick }: any) => {
  const icons: Record<string, any> = {
    grid: <path d="M4 4h4v4H4V4zm6 0h4v4h-4V4zm6 0h4v4h-4V4zM4 10h4v4H4v-4zm6 0h4v4h-4v-4zm6 0h4v4h-4v-4zM4 16h4v4H4v-4zm6 0h4v4h-4v-4zm6 0h4v4h-4v-4z" />,
    lightbulb: <path d="M9 21h6v-1H9v1zm3-19C8.14 2 5 5.14 5 9c0 2.38 1.19 4.47 3 5.74V17c0 .55.45 1 1 1h6c.55 0 1-.45 1-1v-2.26c1.81-1.27 3-3.36 3-5.74 0-3.86-3.14-7-7-7z" />,
    brain: <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />,
    tasks: <path d="M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm-5 14H7v-2h7v2zm3-4H7v-2h10v2zm0-4H7V7h10v2z" />,
    trophy: <path d="M19 5h-2V3H7v2H5c-1.1 0-2 .9-2 2v1c0 2.55 1.92 4.63 4.39 4.94A5.01 5.01 0 0011 15.9V19H7v2h10v-2h-4v-3.1a5.01 5.01 0 003.61-2.96C19.08 11.63 21 9.55 21 7V6c0-1.1-.9-2-2-2zM5 8V7h2v3.82C5.84 10.4 5 9.3 5 8zm14 0c0 1.3-.84 2.4-2 2.82V7h2v1z" />,
    history: <path d="M13 3c-4.97 0-9 4.03-9 9H1l3.89 3.89.07.14L9 12H6c0-3.87 3.13-7 7-7s7 3.13 7 7-3.13 7-7 7c-1.93 0-3.68-.79-4.94-2.06l-1.42 1.42C8.27 19.99 10.51 21 13 21c4.97 0 9-4.03 9-9s-4.03-9-9-9zm-1 5v5l4.28 2.54.72-1.21-3.5-2.08V8H12z" />
  };
  return (
    <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-3.5 rounded-xl transition-all ${active ? 'bg-white/10 text-indigo-400 font-black' : 'text-slate-500 hover:text-slate-200'}`}>
      <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">{icons[icon]}</svg>
      <span className="text-[10px] md:text-[11px] font-black uppercase tracking-widest">{label}</span>
    </button>
  );
};

export default App;

export type Language = 'en' | 'ru' | 'uz';

export type StudentClass = '7A' | '7B' | '8A' | '8B' | '9A' | '9B' | '10A' | '10B' | '11A' | '11B';

export interface Attachment {
  mimeType: string;
  data: string; // base64
  name: string;
}

export interface UserProfile {
  email: string;
  name: string;
  photo?: string;
  bio?: string;
  interests: string[];
  studentClass: StudentClass;
  language: Language;
  xp: number;
  level: number;
  isAdmin: boolean;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  attachment?: Attachment;
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  type: 'teacher' | 'coach' | 'trainer';
  lastUpdated: number;
}

export interface Task {
  id: string;
  title: string;
  difficulty: 'easy' | 'medium' | 'challenge';
  description: string;
  xpReward: number;
}

export interface Node {
  id: string;
  x: number;
  y: number;
  text: string;
  color: string;
  isGenerating?: boolean;
}

import React, { useState, useRef, useEffect } from 'react';
import { Node } from '../types';

interface NodeItemProps {
  node: Node;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onUpdate: (id: string, updates: Partial<Node>) => void;
  onExpand: (id: string) => void;
  onDelete: (id: string) => void;
}

export const NodeItem: React.FC<NodeItemProps> = ({ 
  node, 
  isSelected, 
  onSelect, 
  onUpdate, 
  onExpand,
  onDelete
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragOffset = useRef({ x: 0, y: 0 });

  const startDragging = (clientX: number, clientY: number) => {
    onSelect(node.id);
    setIsDragging(true);
    dragOffset.current = {
      x: clientX - node.x,
      y: clientY - node.y
    };
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    e.stopPropagation();
    startDragging(e.clientX, e.clientY);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    e.stopPropagation();
    const touch = e.touches[0];
    startDragging(touch.clientX, touch.clientY);
  };

  useEffect(() => {
    const handleMove = (clientX: number, clientY: number) => {
      if (isDragging) {
        onUpdate(node.id, {
          x: clientX - dragOffset.current.x,
          y: clientY - dragOffset.current.y
        });
      }
    };

    const onMouseMove = (e: MouseEvent) => handleMove(e.clientX, e.clientY);
    const onTouchMove = (e: TouchEvent) => {
      if (isDragging) {
        const touch = e.touches[0];
        handleMove(touch.clientX, touch.clientY);
      }
    };

    const stopDragging = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', stopDragging);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', stopDragging);
    }

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', stopDragging);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', stopDragging);
    };
  }, [isDragging, node.id, onUpdate]);

  return (
    <div
      onMouseDown={handleMouseDown}
      onTouchStart={handleTouchStart}
      className={`absolute cursor-grab active:cursor-grabbing select-none rounded-[1.5rem] p-5 shadow-2xl border-2 transition-all duration-200 ${
        isSelected ? 'border-indigo-500 ring-4 ring-indigo-500/20 scale-105' : 'border-white/10'
      } ${node.color} text-white flex flex-col items-center justify-center min-w-[180px] max-w-[280px] z-10`}
      style={{
        left: node.x,
        top: node.y,
        touchAction: 'none'
      }}
    >
      {node.isGenerating && (
        <div className="absolute inset-0 bg-white/20 animate-pulse rounded-[1.5rem]" />
      )}

      <textarea
        className="bg-transparent border-none outline-none text-center font-bold w-full resize-none placeholder-white/50 text-sm"
        value={node.text}
        onChange={(e) => onUpdate(node.id, { text: e.target.value })}
        onMouseDown={(e) => e.stopPropagation()}
        onTouchStart={(e) => e.stopPropagation()}
        rows={2}
        placeholder="Think something..."
      />

      <div className="flex gap-2 mt-4 pt-3 border-t border-white/20 w-full justify-center">
        <button
          onClick={(e) => { e.stopPropagation(); onExpand(node.id); }}
          className="p-1.5 hover:bg-white/20 rounded-lg transition-colors text-[10px] font-black uppercase tracking-widest flex items-center gap-1"
          disabled={node.isGenerating}
        >
          <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
          Expand
        </button>
        <button
          onClick={(e) => { e.stopPropagation(); onDelete(node.id); }}
          className="p-1.5 hover:bg-red-500/50 rounded-lg transition-colors text-xs"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
          </svg>
        </button>
      </div>
    </div>
  );
};

