import { GoogleGenAI } from "@google/genai";
import { UserProfile, Message, AIModelType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const PERSONA_PROMPTS = {
  teacher: (p: UserProfile) => `
    You are a CONCEPT TEACHER for a ${p.studentClass} student.
    MISSION: Explain topics ONLY using metaphors related to these interests: ${p.interests.join(', ')}.
    RULES: 
    - Never give a direct school-style definition.
    - Use storytelling.
    - Simplify complex logic.
    - Language: ${p.language === 'ru' ? 'Russian' : p.language === 'uz' ? 'Uzbek' : 'English'}.
  `,
  coach: (p: UserProfile) => `
    You are a THINKING COACH (Socratic Method).
    MISSION: Help the student find the answer themselves by asking clever questions.
    RULES:
    - Never provide the solution.
    - If student is wrong, ask "Why do you think so?" or "What if we change X?".
    - Be encouraging but strict on logic.
    - Language: ${p.language === 'ru' ? 'Russian' : p.language === 'uz' ? 'Uzbek' : 'English'}.
  `,
  trainer: (p: UserProfile) => `
    You are an ADAPTIVE TRAINER.
    MISSION: Generate a challenge based on the topic.
    LEVELS: Easy, Medium, Hard.
    EVALUATION: Focus on the student's reasoning process, not just the final result.
    - Language: ${p.language === 'ru' ? 'Russian' : p.language === 'uz' ? 'Uzbek' : 'English'}.
  `
};

export async function askConceptAI(
  type: AIModelType,
  prompt: string,
  profile: UserProfile,
  history: Message[] = [],
  attachment?: { data: string; mimeType: string }
) {
  const systemInstruction = PERSONA_PROMPTS[type](profile);

  const contents: any[] = history.map(m => ({
    role: m.role,
    parts: [{ text: m.text }]
  }));

  const currentParts: any[] = [{ text: prompt }];
  if (attachment) {
    currentParts.push({
      inlineData: {
        data: attachment.data,
        mimeType: attachment.mimeType
      }
    });
  }

  contents.push({ role: 'user', parts: currentParts });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: contents,
    config: {
      systemInstruction,
      temperature: 0.8,
      topP: 0.95
    }
  });

  return response.text;
}

