                      <th className="p-8 text-[10px] font-black uppercase tracking-widest opacity-50">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {students.filter(s => s.email !== ADMIN_EMAIL).map(s => (
                      <tr key={s.email} className={`border-t ${themeClasses.border}`}>
                        <td className="p-8 font-bold">{s.name}<br/><span className="text-[10px] opacity-40 uppercase font-black">{s.email}</span></td>
                        <td className="p-8 font-black text-indigo-500">{s.xp}</td>
                        <td className="p-8 flex gap-3">
                           <button onClick={() => setStudents(students.map(st => st.email===s.email ? {...st, xp: st.xp+100, level: Math.floor((st.xp+100)/100)+1} : st))} className="bg-indigo-600 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase hover:scale-105 transition-all">+100 XP</button>
