                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>
      {isMobileMenuOpen && <div className="fixed inset-0 bg-black/90 z-40 lg:hidden" onClick={() => setIsMobileMenuOpen(false)} />}
    </div>
  );
};

