    e.preventDefault();
    setAuthError(null);
    const fd = new FormData(e.currentTarget);
    const email = (fd.get('email') as string).toLowerCase().trim();
    const pass = fd.get('password') as string;

    if (!email || !pass) return;

    if (view === 'register') {
      if (MockBackend.getUsers().find(s => s.email === email)) {
        setAuthError("Email already exists.");
        return;
      }
      const interests = INTERESTS.filter(i => fd.get(`interest-${i}`));
      const newUser: UserProfile = {
        email, name: fd.get('name') as string,
        password: pass,
        studentClass: fd.get('class') as StudentClass,
        language: lang,
        interests: interests.length ? interests : ['Science'],
        xp: 0, level: 1, isAdmin: false,
        bio: ''
      };
      MockBackend.saveUser(newUser);
      setUser(newUser);
      setStudents(MockBackend.getUsers());
      setView('dash');
    } else {
      const authenticatedUser = MockBackend.login(email, pass);
      if (authenticatedUser) {
        setUser(authenticatedUser);
        setView('dash');
      } else {
        setAuthError(t.authError);
      }
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      const base64 = (evt.target?.result as string).split(',')[1];
      setAttachment({ data: base64, mimeType: file.type, name: file.name });
    };
    reader.readAsDataURL(file);
  };

  const sendMessage = async () => {
    if ((!input.trim() && !attachment) || !user) return;
    setIsLoading(true);

    let sessionId = currentSessionId;
    if (!sessionId) {
      sessionId = Date.now().toString();
      setCurrentSessionId(sessionId);
    }

    const userMsg: Message = { role: 'user', text: input, timestamp: Date.now(), attachment: attachment || undefined };
    const currentMessages = [...messages, userMsg];
    setMessages(currentMessages);
    setInput('');
    setAttachment(null);

    try {
      const aiResponse = await askThinkFlowAI(activeAI, input, user, messages, attachment || undefined);
      const modelMsg: Message = { role: 'model', text: aiResponse, timestamp: Date.now() };
      const updatedMessages = [...currentMessages, modelMsg];
      setMessages(updatedMessages);

      const sessionTitle = currentMessages[0].text.slice(0, 30) || "New Conversation";
      const newSession: ChatSession = { id: sessionId, title: sessionTitle, type: activeAI, messages: updatedMessages, lastUpdated: Date.now() };
      MockBackend.saveSession(user.email, newSession);
      setSessions(MockBackend.getUserSessions(user.email));

      const updatedUser = MockBackend.updateXP(user.email, 15);
      if (updatedUser) {
        setUser(updatedUser);
        setStudents(MockBackend.getUsers());
      }
    } catch (err) {
      setMessages([...currentMessages, { role: 'model', text: "Backend sync error. Check connectivity.", timestamp: Date.now() }]);
    } finally {
      setIsLoading(false);
    }
  };

  const loadSession = (s: ChatSession) => {
    setCurrentSessionId(s.id);
    setMessages(s.messages);
    setActiveAI(s.type);
    setView('chat');
    setIsMobileMenuOpen(false);
  };

